INSERT INTO products (id, product_name, price, discription, category, availability, image_url, room, material, color, dimensions, collection, sku, slug, warranty, weight_kg, category_id) VALUES
(1011681, 'Ghế cafe DAILY GCF-038', 0, 'Kích thước ghế: Cao tổng thể 820mm × Rộng 460mm × Sâu 500mm × Cao mặt ngồi 450mm Quy cách: Ghế nhựa phong cách hiện đại – tối giản, lưng tựa cong nhẹ nâng đỡ lưng, mặt ngồi vừa vặn cân đối, kiểu dáng gọn gàng tối ưu diện tích. Chất liệu: Khung nhựa cao cấp, chịu lực tốt, chống cong vênh. Chống ẩm, chống mối mọt, bề mặt nhẵn mịn dễ vệ sinh. Trọng lượng nhẹ, dễ di chuyển và sắp xếp. Phong cách: Hiện đại, tinh tế, dễ phối hợp với nhiều phong cách nội thất (Scandinavian, Minimalist, Vintage). Công năng: Ghế ngồi cho quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, văn phòng, showroom, homestay, khu vực chờ. Ứng dụng: Linh hoạt cho nhiều không gian, phù hợp môi trường có tần suất sử dụng cao, tối ưu chi phí đầu tư.', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-038-1.jpg', NULL, NULL, NULL, 'Cao tổng thể 820mm × Rộng 460mm × Sâu 500mm × Cao mặt ngồi 450mm', 'Bluewood', 'GCF-038', 'ghe-cafe-daily-gcf-038', NULL, NULL, 163),
(1011856, 'Ghế cafe DAILY GCF-063', 690000, 'Ghế cafe DAILY GCF-063 – Thiết kế hiện đại, bền bỉ cho không gian quán cafe Ghế cafe DAILY GCF-063 là dòng ghế nhựa cao cấp được thiết kế theo phong cách hiện đại, tinh tế và tối ưu công năng sử dụng. Sản phẩm phù hợp cho nhiều không gian như quán cafe, nhà hàng, quán ăn, văn phòng, khu vực tiếp khách hoặc sử dụng trong gia đình. Với kiểu dáng gọn gàng, chất liệu bền bỉ và thiết kế thoải mái, DAILY GCF-063 mang lại trải nghiệm ngồi dễ chịu và góp phần nâng cao tính thẩm mỹ cho không gian. Thiết kế hiện đại, tinh tế Ghế cafe DAILY GCF-063 sở hữu kiểu dáng đơn giản nhưng không kém phần sang trọng, phù hợp với nhiều phong cách nội thất khác nhau từ hiện đại đến tối giản. Phần tựa lưng được thiết kế vừa vặn với dáng người, giúp nâng đỡ lưng hiệu quả và tạo cảm giác thoải mái khi ngồi lâu. Mặt ghế rộng rãi, kết cấu chắc chắn, tạo sự ổn định và an toàn trong quá trình sử dụng. Các đường nét được hoàn thiện tỉ mỉ, mang đến tổng thể hài hòa và chuyên nghiệp cho không gian. Chất liệu nhựa PP cao cấp, độ bền vượt trội Sản phẩm được làm từ nhựa PP cao cấp, có khả năng chịu lực tốt và độ bền cao. Chất liệu này giúp ghế chống cong vênh, hạn chế nứt vỡ trong quá trình sử dụng lâu dài. Ngoài ra, nhựa PP còn có khả năng chống ẩm, chống bám bẩn và dễ dàng vệ sinh, phù hợp với môi trường sử dụng thường xuyên như quán cafe hoặc nhà hàng. Bề mặt ghế được xử lý mịn, giúp tăng tính thẩm mỹ và đảm bảo an toàn khi sử dụng. Kích thước tiêu chuẩn, tối ưu trải nghiệm người dùng Với chiều cao mặt ngồi 460 mm, ghế cafe DAILY GCF-063 phù hợp với đa số chiều cao bàn cafe và bàn ăn tiêu chuẩn. Kích thước ghế được thiết kế khoa học giúp người ngồi giữ tư thế thoải mái, hạn chế mỏi lưng và tạo sự dễ chịu trong thời gian dài. Thiết kế gọn nhẹ giúp dễ dàng di chuyển, sắp xếp hoặc bố trí trong nhiều không gian khác nhau mà không chiếm nhiều diện tích. Thông số kỹ thuật ghế cafe DAILY GCF-063 Ứng dụng linh hoạt cho nhiều không gian Ghế cafe DAILY GCF-063 là lựa chọn lý tưởng cho nhiều mục đích sử dụn...', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/03/ghe-cafe-daily-gcf-063-2.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1011856', 'ghe-cafe-daily-gcf-063', NULL, NULL, 163),
(1011888, 'Ghế cafe DAILY GCF-064', 785000, 'Ghế cafe DAILY GCF-064 – Thiết kế hiện đại, bền đẹp cho không gian quán và gia đình Ghế cafe DAILY GCF-064 là dòng ghế cafe hiện đại được thiết kế tối giản nhưng tinh tế, phù hợp với nhiều không gian như quán cafe, nhà hàng, sân vườn, ban công hay khu vực tiếp khách. Sản phẩm nổi bật với kiểu dáng thanh lịch, chất liệu nhựa PP cao cấp bền bỉ cùng thiết kế tựa lưng và tay vịn thoải mái, mang lại trải nghiệm sử dụng lâu dài và tiện nghi. Với kiểu dáng gọn gàng, màu sắc trang nhã và khả năng chịu lực tốt, ghế cafe DAILY GCF-064 là lựa chọn lý tưởng cho những không gian cần sự chuyên nghiệp, hiện đại và tối ưu chi phí. Thiết kế hiện đại, tinh tế Ghế cafe DAILY GCF-064 sở hữu thiết kế đơn giản nhưng không kém phần sang trọng, dễ dàng kết hợp với nhiều phong cách nội thất khác nhau từ hiện đại, tối giản đến tự nhiên. Phần tựa lưng và mặt ngồi được thiết kế dạng lưới thông thoáng giúp tăng tính thẩm mỹ đồng thời tạo cảm giác thoải mái khi sử dụng trong thời gian dài. Tay vịn hai bên được bo cong mềm mại giúp nâng đỡ cánh tay, mang lại tư thế ngồi thư giãn. Chân ghế chắc chắn, kết cấu ổn định giúp ghế đứng vững trên nhiều bề mặt khác nhau, phù hợp cho cả không gian trong nhà và ngoài trời. Chất liệu nhựa PP cao cấp, bền bỉ Ghế được sản xuất từ nhựa PP cao cấp có độ bền cao, chịu lực tốt và chống va đập hiệu quả. Chất liệu này giúp ghế có trọng lượng nhẹ, dễ dàng di chuyển và sắp xếp. Ngoài ra, nhựa PP có khả năng chống ẩm, chống ăn mòn và dễ vệ sinh, giúp sản phẩm luôn giữ được vẻ đẹp lâu dài trong quá trình sử dụng. Đây là lựa chọn phù hợp cho môi trường quán cafe có tần suất sử dụng cao. Kích thước tiêu chuẩn, tối ưu trải nghiệm ngồi Ghế cafe DAILY GCF-064 được thiết kế theo tiêu chuẩn giúp người dùng ngồi thoải mái và đúng tư thế. Thông số kỹ thuật: Chiều cao tổng thể: 810 mm Chiều sâu: 570 mm Chiều rộng: 530 mm Chiều cao mặt ngồi: 460 mm Kích thước hợp lý giúp ghế phù hợp với đa số bàn cafe và bàn ăn, đảm bảo sự tiện lợi trong quá trình sử dụng. Ứng dụng đa dạng tron...', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/03/ghe-cafe-daily-gcf-064-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1011888', 'ghe-cafe-daily-gcf-064', NULL, NULL, 163),
(1013241, 'Ghế văn phòng NEO GVP-022', 795000, 'Kích thước: Chiều cao mặt ngồi: 43–53 cm Ngang ghế: 49 cm Sâu ghế: 50 cm Tổng chiều cao: 87–97 cm Quy cách: Ghế văn phòng hiện đại – thiết kế tối giản, thoáng khí, phù hợp nhiều không gian làm việc (văn phòng, phòng họp, học tập tại nhà, startup). Chất liệu: Lưng nhựa bọc lưới: thoáng khí, có cơ chế gật gù thư giãn Đệm mút bọc lưới: êm ái, đàn hồi tốt, giữ form lâu dài Tay ghế nhựa cong cố định: chắc chắn, hỗ trợ tư thế tự nhiên Piston thủy lực: nâng hạ chiều cao linh hoạt Chân sao nhựa đúc: chịu lực tốt, bền bỉ Bánh xe nhựa bọc cao su: di chuyển nhẹ nhàng, giảm tiếng ồn, bảo vệ mặt sàn Phong cách: Hiện đại, tối giản, tiện dụng – phù hợp nhiều phong cách nội thất văn phòng.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-022-4.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013241', 'ghe-van-phong-neo-gvp-022', NULL, NULL, 161),
(1013264, 'Ghế văn phòng NEO GVP-026', 915000, 'Kích thước: Chiều cao mặt ngồi: 38–48 cm Ngang: 60 cm Sâu: 47 cm Cao tổng thể: 88–98 cm Quy cách: Ghế văn phòng công thái học – thiết kế hiện đại, trẻ trung, gam màu trắng đen sang trọng. Phù hợp văn phòng công ty, phòng họp, góc làm việc tại nhà hoặc không gian học tập. Chất liệu: Lưng nhựa bọc lưới: thoáng khí, ôm sát cơ thể, hỗ trợ cột sống Đệm mút bọc lưới: êm ái, đàn hồi tốt, hạn chế nóng bí Tay ghế nhựa điều chỉnh: linh hoạt, giảm áp lực vai và cánh tay Piston thủy lực: nâng hạ chiều cao mượt mà Chân nhựa PP cao cấp: nhẹ nhưng chắc chắn, chịu lực tốt Bánh xe nhựa bọc cao su: di chuyển êm ái, giảm tiếng ồn, bảo vệ mặt sàn Phong cách: Hiện đại, công thái học, sang trọng – dễ phối hợp nhiều phong cách nội thất. Ứng dụng: Văn phòng công ty, phòng họp, phòng học tập, góc làm việc cá nhân.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-026-4.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013264', 'ghe-van-phong-neo-gvp-026', NULL, NULL, 161),
(1013338, 'Ghế văn phòng NEO GVP-036', 1125000, 'Kích thước: Lưng ghế: 53 cm Nệm ghế: 53 cm Chân ghế: 63 cm Tổng chiều cao: 117–127 cm Quy cách: Ghế công thái học hiện đại – thiết kế tối giản, sang trọng, phù hợp văn phòng công ty, phòng làm việc cá nhân, phòng gaming hoặc góc học tập. Chất liệu: Lưng lưới thoáng khí: đàn hồi tốt, giảm nóng bí Đệm ngồi xốp bọt biển bọc vải: êm ái, thoáng khí Tựa đầu tích hợp: hỗ trợ cổ gáy Chân sao 5 cánh chắc chắn: ổn định, chịu lực tốt Bánh xe xoay linh hoạt: di chuyển nhẹ nhàng, hạn chế tiếng ồn Piston nâng hạ: điều chỉnh chiều cao dễ dàng Phong cách: Công thái học hiện đại, thanh lịch, nhiều phiên bản màu sắc – dễ phối hợp nội thất từ văn phòng chuyên nghiệp đến không gian cá nhân.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-036-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013338', 'ghe-van-phong-neo-gvp-036', NULL, NULL, 161),
(1013255, 'Ghế văn phòng NEO GVP–023', 1170000, 'Kích thước: R580 × D600 × H800–1000 mm Quy cách: Ghế xoay văn phòng hiện đại – thiết kế tối giản, tinh tế, phù hợp nhiều không gian (phòng làm việc cá nhân, văn phòng công ty, phòng họp, khu vực tiếp khách). Chất liệu: Lưng và mặt ngồi bằng lưới: thoáng khí, hạn chế nóng bí, ngồi lâu vẫn dễ chịu Khung và chân inox: chắc chắn, chống gỉ sét, tăng độ bền Piston nâng hạ: điều chỉnh chiều cao linh hoạt Bánh xe xoay 360°: di chuyển nhẹ nhàng, tiện lợi Phong cách: Hiện đại, tối giản, sang trọng – nâng cao tính thẩm mỹ cho không gian làm việc. Ứng dụng: Văn phòng công ty, phòng họp, phòng làm việc cá nhân, khu vực tiếp khách.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-022-2-1.jpg', NULL, NULL, NULL, 'R580 × D600 × H800–1000 mm', 'Bluewood', 'BLUEWOOD-1013255', 'ghe-van-phong-neo-gvp-023', NULL, NULL, 161),
(1013856, 'Bàn cafe DAILY BCF-003', 1275000, 'Kích thước: 600 × 600 × 730 mm – nhỏ gọn, tiêu chuẩn, dễ bố trí nhiều không gian. Quy cách: Bàn cafe hiện đại – thiết kế mặt bàn tròn, chân trụ thanh lịch. Phù hợp quán cafe, showroom, văn phòng tiếp khách, căn hộ, studio. Chất liệu: Mặt bàn MDF phủ sơn PU: nhẵn mịn, sang trọng, chống trầy nhẹ, dễ vệ sinh Chân sắt sơn tĩnh điện: chắc chắn, chống gỉ sét, bền màu, ổn định khi sử dụng Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Scandinavian , Contemporary , Modern .', 'Bàn', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-cafe-daily-bcf-003-1.jpg', NULL, NULL, NULL, '600 × 600 × 730 mm – nhỏ gọn, tiêu chuẩn, dễ bố trí nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013856', 'ban-cafe-daily-bcf-003', NULL, NULL, 96),
(1013863, 'Bàn cafe DAILY BCF-001', 1379000, 'Kích thước: 600 × 600 × 730 mm – nhỏ gọn, tiêu chuẩn, phù hợp nhiều không gian. Quy cách: Bàn cafe tròn hiện đại – thiết kế tối giản, tone trắng thanh lịch, chân trụ cách điệu. Phù hợp quán cafe, văn phòng, showroom, căn hộ, studio. Chất liệu: Mặt bàn MDF phủ sơn PU: nhẵn mịn, sang trọng, chống trầy nhẹ, dễ vệ sinh Chân sắt sơn tĩnh điện: chắc chắn, chống gỉ sét, bền màu, ổn định khi sử dụng Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Modern , Minimalism , Scandinavian .', 'Bàn', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-cafe-daily-bcf-001-3.jpg', NULL, NULL, NULL, '600 × 600 × 730 mm – nhỏ gọn, tiêu chuẩn, phù hợp nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013863', 'ban-cafe-daily-bcf-001', NULL, NULL, 96),
(1013310, 'Ghế văn phòng NEO GVP-032', 1410000, 'Kích thước & góc ngả: Ngả linh hoạt: 90°–135° Tựa lưng chữ S ôm sát cột sống Có gác chân kéo gọn tiện lợi Quy cách: Ghế công thái học cao cấp – thiết kế hiện đại, sang trọng, phù hợp văn phòng doanh nghiệp, phòng họp, góc làm việc tại nhà hoặc không gian coworking. Chất liệu: Lưng lưới đàn hồi cao cấp: thoáng khí, nâng đỡ cơ thể Đệm ngồi bọt biển dày bọc lưới: êm ái, đàn hồi tốt Tựa đầu rộng rãi: hỗ trợ cổ và vai gáy Khung nhựa chịu lực + chân nhựa chắc chắn: ổn định, bền bỉ Bánh xe xoay linh hoạt: di chuyển nhẹ nhàng, ít tiếng ồn Phong cách: Công thái học hiện đại, tinh gọn, gam màu trung tính dễ phối nội thất từ tối giản đến chuyên nghiệp.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-032-4.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013310', 'ghe-van-phong-neo-gvp-032', NULL, NULL, 161),
(1013321, 'Ghế văn phòng NEO GVP-034', 1440000, 'Kích thước: Chiều cao mặt ngồi: 44–54 cm Chiều cao tổng thể: 125–135 cm Rộng đệm: 50 cm Sâu đệm: 50 cm Khoảng cách tay ghế: 60 cm Chiều dài tay ghế: 45 cm Quy cách: Ghế công thái học cao cấp – thiết kế hiện đại, sang trọng, gam màu đen trắng nổi bật. Phù hợp dân văn phòng, người làm việc tại nhà, freelancer, game thủ. Chất liệu: Khung nhựa PP cao cấp: chịu lực tốt, bền bỉ Tựa lưng lưới đàn hồi: thoáng khí, ôm dáng cột sống Đệm mút bọc lưới: êm ái, hạn chế xẹp lún Tựa đầu êm ái: hỗ trợ cổ và vai gáy Gác chân nhựa kéo gọn: tiện lợi nghỉ ngơi Piston thủy lực: nâng hạ mượt mà Chân sao nhựa đúc nguyên khối: ổn định, chắc chắn Bánh xe cao su: di chuyển nhẹ nhàng, chống ồn, hạn chế trầy sàn Phong cách: Công thái học hiện đại, tiện nghi – phù hợp nhiều không gian làm việc chuyên nghiệp và cá nhân.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-034-6.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013321', 'ghe-van-phong-neo-gvp-034', NULL, NULL, 161),
(1001585, 'Ghế ăn LUNO GAN-029', 1485000, 'Kích thước: Cao tổng ~940mm, cao tựa lưng ~630mm, rộng ~480mm Quy cách: Ghế ăn hiện đại pha chút cổ điển, tựa lưng bo tròn mềm mại, phối da PU và vải bố cao cấp, chân sắt sơn tĩnh điện đen với chi tiết mạ vàng sang trọng Chất liệu: Da PU mịn chống thấm, vải bố dệt cao cấp thoáng khí, khung chân sắt sơn tĩnh điện chắc chắn, phụ kiện mạ vàng tinh tế, nhập khẩu nguyên chiếc Màu sắc: Vàng be thanh lịch, Nâu caramel ấm áp, Caro trắng đen thời thượng Phong cách: Hiện đại pha cổ điển, sang trọng, tinh tế Ứng dụng: Ghế ăn gia đình, ghế cafe cao cấp, ghế nhà hàng, khách sạn, phòng chờ', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-029-2.jpg', NULL, 'Da PU mịn chống thấm, vải bố dệt cao cấp thoáng khí, khung chân sắt sơn tĩnh điện chắc chắn, phụ kiện mạ vàng tinh tế, nhập khẩu nguyên chiếc', 'Vàng be thanh lịch, Nâu caramel ấm áp, Caro trắng đen thời thượng', 'Cao tổng ~940mm, cao tựa lưng ~630mm, rộng ~480mm', 'Bluewood', 'GAN-029', 'ghe-an-luno-gan-029', NULL, NULL, 162),
(1011987, 'Ghế cafe DAILY GCF-081', 1985000, 'Ghế cafe DAILY GCF-081 – Thiết kế hiện đại, bền bỉ cho không gian quán và nội thất hiện đại Ghế cafe DAILY GCF-081 là dòng ghế cafe thiết kế tối giản, hiện đại, phù hợp với nhiều không gian như quán cafe, nhà hàng, văn phòng, khu vực tiếp khách hoặc sử dụng trong gia đình. Sản phẩm nổi bật với kiểu dáng thanh lịch, chất liệu bền bỉ cùng thiết kế tối ưu sự thoải mái cho người sử dụng. Với sự kết hợp giữa nhựa PP cao cấp và chân sắt chắc chắn, ghế cafe DAILY GCF-081 mang đến độ bền cao, dễ vệ sinh và khả năng sử dụng lâu dài trong nhiều môi trường khác nhau. Thiết kế hiện đại, tinh tế Ghế cafe DAILY GCF-081 sở hữu kiểu dáng đơn giản nhưng tinh tế, phù hợp với xu hướng nội thất hiện đại. Phần tựa lưng được thiết kế cong nhẹ giúp nâng đỡ lưng hiệu quả, tạo cảm giác thoải mái khi ngồi trong thời gian dài. Mặt ghế rộng vừa phải, độ cao tiêu chuẩn giúp người ngồi có tư thế ổn định. Thiết kế gọn gàng giúp dễ dàng sắp xếp, bố trí trong nhiều không gian khác nhau mà không gây cảm giác chật chội. Chân ghế thanh mảnh nhưng chắc chắn, tạo tổng thể hài hòa và tăng tính thẩm mỹ cho sản phẩm. Chất liệu bền bỉ, sử dụng lâu dài Ghế được làm từ nhựa PP cao cấp có khả năng chịu lực tốt, chống cong vênh và hạn chế trầy xước trong quá trình sử dụng. Bề mặt nhựa mịn giúp dễ lau chùi, vệ sinh nhanh chóng. Phần chân ghế được làm từ sắt sơn tĩnh điện chắc chắn, tăng khả năng chịu tải và đảm bảo độ ổn định khi sử dụng. Lớp sơn giúp chống gỉ sét, nâng cao tuổi thọ sản phẩm ngay cả trong môi trường sử dụng thường xuyên. Kích thước tiêu chuẩn, tối ưu trải nghiệm ngồi Ghế cafe DAILY GCF-081 được thiết kế theo kích thước tiêu chuẩn, phù hợp với bàn cafe, bàn ăn hoặc bàn làm việc. Thông số kỹ thuật: Kích thước này giúp người ngồi có tư thế thoải mái, dễ dàng kết hợp với nhiều loại bàn khác nhau. Ứng dụng đa dạng trong nhiều không gian Ghế cafe DAILY GCF-081 phù hợp với nhiều mục đích sử dụng như: Không gian quán cafe hiện đại Nhà hàng, quán ăn Phòng họp, văn phòng Khu vực tiếp khách Không gian n...', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/03/ghe-cafe-daily-gcf-081-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1011987', 'ghe-cafe-daily-gcf-081', NULL, NULL, 163),
(1011972, 'Ghế cafe DAILY GCF-077', 2275000, 'Ghế cafe DAILY GCF-077 – Thiết kế hiện đại, nhẹ nhàng cho không gian quán cafe Ghế cafe DAILY GCF-077 là mẫu ghế hiện đại được thiết kế theo phong cách tối giản, phù hợp với nhiều không gian như quán cafe, nhà hàng, văn phòng, khu vực tiếp khách hoặc sử dụng trong gia đình. Với kiểu dáng thanh lịch, chất liệu bền bỉ cùng kích thước tiêu chuẩn, sản phẩm mang lại sự thoải mái khi sử dụng và góp phần nâng cao tính thẩm mỹ cho không gian. Thiết kế hiện đại, tối giản Ghế cafe DAILY GCF-077 sở hữu thiết kế tinh gọn với các đường nét mềm mại, tạo cảm giác thanh thoát và hiện đại. Phần tựa lưng cong nhẹ ôm sát lưng người ngồi, giúp nâng đỡ cơ thể hiệu quả và tạo cảm giác thoải mái trong thời gian dài. Kiểu dáng ghế gọn gàng, dễ dàng bố trí trong nhiều không gian khác nhau từ quán cafe phong cách hiện đại, tối giản đến không gian nội thất trẻ trung. Màu sắc đa dạng giúp dễ dàng kết hợp với nhiều phong cách trang trí. Chất liệu bền bỉ, chắc chắn Sản phẩm được làm từ nhựa PP cao cấp chắc chắn, mang lại độ bền cao và khả năng chịu lực tốt. Nhựa PP có đặc tính nhẹ, chống thấm nước, dễ vệ sinh và ít bám bẩn, phù hợp cho môi trường sử dụng thường xuyên như quán cafe hoặc nhà hàng. Phần chân giúp tăng độ ổn định, đảm bảo an toàn khi sử dụng và kéo dài tuổi thọ sản phẩm. Kích thước tiêu chuẩn, tối ưu trải nghiệm Ghế cafe DAILY GCF-077 được thiết kế với kích thước phù hợp với vóc dáng người dùng và nhiều loại bàn khác nhau. Kích thước này giúp người ngồi có tư thế thoải mái, dễ dàng kết hợp với bàn cafe, bàn ăn hoặc bàn làm việc. Ứng dụng đa dạng trong nhiều không gian Nhờ thiết kế linh hoạt và chất liệu bền bỉ, ghế cafe DAILY GCF-077 phù hợp sử dụng trong nhiều môi trường khác nhau: Quán cafe, trà sữa, nhà hàng Khu vực tiếp khách, phòng chờ Không gian làm việc, văn phòng Gia đình, phòng ăn hoặc ban công Sản phẩm giúp tạo nên không gian hiện đại, gọn gàng và chuyên nghiệp. Ưu điểm nổi bật của ghế cafe DAILY GCF-077 Thiết kế hiện đại, kiểu dáng tinh tế Tựa lưng cong tạo cảm giác th...', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/03/ghe-cafe-daily-gcf-077-2.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1011972', 'ghe-cafe-daily-gcf-077', NULL, NULL, 163),
(1000258, 'Bàn trang điểm LANO BTD-001', 2450000, 'Kích thước tổng thể: W900 x D500 x H1330 mm Chiều cao chân bàn: 570 mm Gương: Hình bầu dục, kích thước tiêu chuẩn giúp phản chiếu tốt Ngăn kéo: 2 ngăn lớn phía dưới, kệ nhỏ phía trên để đựng mỹ phẩm và phụ kiện', 'Bàn trang điểm gỗ công nghiệp', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ban-trang-diem-001-r.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BTD-001', 'ban-trang-diem-lano-btd-001', NULL, NULL, 172),
(1013788, 'Tủ trưng bày LARA TTB-001', 2945000, 'Kích thước: 1500 × 400 × 860 mm – thiết kế ngang, gọn gàng, tối ưu diện tích. Quy cách: Tủ trưng bày decor – tone màu đen sang trọng, dáng đứng thanh lịch. Phù hợp phòng khách, phòng ăn, showroom, studio, quán café, khu vực trưng bày sản phẩm. Chất liệu: Khung gỗ thông tự nhiên: chắc chắn, chịu lực tốt, hạn chế cong vênh Bề mặt hoàn thiện tỉ mỉ: đẹp tự nhiên, dễ vệ sinh Cánh mở tiện lợi: thao tác nhẹ nhàng, thuận tiện Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Modern , Minimalism , Scandinavian .', 'Tủ và kệ', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/tu-trung-bay-lara-ttb-001-1.jpg', NULL, NULL, NULL, '1500 × 400 × 860 mm – thiết kế ngang, gọn gàng, tối ưu diện tích.', 'Bluewood', 'BLUEWOOD-1013788', 'tu-trung-bay-lara-ttb-001', NULL, NULL, 85),
(1013718, 'Ghế sofa phòng khách JUNO GSF-111', 3435000, 'Kích thước: 590 × 790 × 705 mm – nhỏ gọn, dễ bố trí nhiều không gian. Quy cách: Ghế sofa đơn – thiết kế tối giản, tinh tế. Phù hợp phòng khách, phòng ngủ, góc đọc sách, homestay, studio, showroom, quán café hiện đại. Chất liệu: Khung: gỗ thông + Plywood chắc chắn, ổn định, hạn chế cong vênh Chân: gỗ cao su màu tự nhiên, mộc mạc, sang trọng Đệm ngồi: Mouse cao cấp + gòn tấm 200gr, êm ái, đàn hồi tốt Phong cách: Hiện đại – tối giản – thanh lịch. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Sofa phòng khách', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-phong-khach-juno-gsf-111-4.jpg', NULL, NULL, NULL, '590 × 790 × 705 mm – nhỏ gọn, dễ bố trí nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013718', 'ghe-sofa-phong-khach-juno-gsf-111', NULL, NULL, 133),
(1013873, 'Bàn cafe DAILY BCF-002', 3575000, 'Kích thước: 800 × 600 × 765 mm – gọn gàng, tiêu chuẩn, phù hợp cho 2–4 người sử dụng. Quy cách: Bàn cafe chữ nhật hiện đại – thiết kế vuông vức thanh lịch, mặt bàn dạng nan ngang, tone trắng sang trọng. Phù hợp quán cafe, ban công căn hộ, văn phòng, showroom, studio. Chất liệu: Chân sắt sơn tĩnh điện: chắc chắn, chống gỉ sét, bền màu, ổn định khi sử dụng Mặt bàn nhựa PP cao cấp: chống ẩm, dễ vệ sinh, hạn chế bám bẩn, nhẹ nhưng chắc chắn Phong cách: Hiện đại – tối giản – thanh lịch. Dễ phối hợp với phong cách Modern , Minimalism , Scandinavian .', 'Bàn', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-cafe-daily-bcf-002-1.jpg', NULL, NULL, NULL, '800 × 600 × 765 mm – gọn gàng, tiêu chuẩn, phù hợp cho 2–4 người sử dụng.', 'Bluewood', 'BLUEWOOD-1013873', 'ban-cafe-daily-bcf-002', NULL, NULL, 96),
(1004392, 'Bàn trang điểm CASO BTD-077', 3620000, 'Thiết kế hiện đại sang trọng: Kích thước W1000 x D450 x H1300 mm, gương LED cao cấp, tông màu thanh lịch. Chức năng thông minh: Tích hợp loa Bluetooth, sạc cảm ứng và sạc không dây tiện lợi. Chất liệu cao cấp: Mặt kính cường lực/laminate, thân bàn gỗ MDF chống ẩm, chân kim loại sơn tĩnh điện chắc chắn. Lưu trữ tối ưu & đa năng: Ngăn kéo rộng rãi, thiết kế khoa học, vừa là bàn trang điểm vừa là trung tâm giải trí mini.', 'Bàn trang điểm thông minh', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ban-trang-diem-caso-btd-077.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BTD-077', 'ban-trang-diem-caso-btd-077', NULL, NULL, 171),
(1013821, 'Bàn học LANO BHC-001', 3900000, 'Kích thước: 1400 × 800 × 750 mm – mặt bàn rộng rãi, cân đối cho góc học tập. Quy cách: Bàn học hiện đại – thiết kế vuông vức kết hợp bo cong mềm mại, tone trắng phối hồng/xanh pastel trẻ trung. Tích hợp kệ sách và nhiều ngăn kéo tiện lợi. Chất liệu: MDF chống ẩm: hạn chế cong vênh, mối mọt Bề mặt phủ Melamine: chống trầy nhẹ, dễ vệ sinh, giữ màu sắc bền đẹp Kết cấu chắc chắn: ổn định khi học tập và làm việc Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Bàn', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-hoc-lano-bhc-001-2.jpg', NULL, NULL, NULL, '1400 × 800 × 750 mm – mặt bàn rộng rãi, cân đối cho góc học tập.', 'Bluewood', 'BLUEWOOD-1013821', 'ban-hoc-lano-bhc-001', NULL, NULL, 96),
(1013813, 'Kệ giày LANO KGY-005', 4104000, 'Kích thước: 1200 × 1200 mm – dạng vuông, gọn gàng, cân đối, phù hợp nhiều không gian. Quy cách: Kệ giày hiện đại – thiết kế bo cong mềm mại, tone màu trắng tinh tế. Phù hợp căn hộ, nhà phố, homestay, văn phòng, studio. Chất liệu: MDF chống ẩm: hạn chế cong vênh, co ngót, mối mọt Bề mặt phủ Melamine: chống trầy nhẹ, dễ vệ sinh, giữ màu sắc bền đẹp Bản lề đóng mở êm ái: thao tác thuận tiện, tăng độ bền Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Tủ giày', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ke-giay-lano-kgy-005-4.jpg', NULL, NULL, NULL, '1200 × 1200 mm – dạng vuông, gọn gàng, cân đối, phù hợp nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013813', 'ke-giay-lano-kgy-005', NULL, NULL, 104),
(1013801, 'Bàn trang điểm LANO BTD-078', 4550000, 'Kích thước: 1400 × 800 × 750 mm – gọn gàng, cân đối, phù hợp nhiều không gian phòng ngủ. Quy cách: Bàn trang điểm hiện đại – thiết kế bo cong mềm mại, tone vân gỗ phối trắng tinh tế. Phù hợp phòng ngủ master, căn hộ chung cư, nhà phố, homestay cao cấp. Chất liệu: MDF chống ẩm: hạn chế cong vênh, co ngót Bề mặt phủ Melamine: chống trầy, dễ vệ sinh, giữ màu sắc bền đẹp Ray trượt giảm chấn cao cấp: đóng mở ngăn kéo êm ái, hạn chế tiếng ồn Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Bàn trang điểm gỗ công nghiệp', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-trang-diem-lano-btd-078-1.jpg', NULL, NULL, NULL, '1400 × 800 × 750 mm – gọn gàng, cân đối, phù hợp nhiều không gian phòng ngủ.', 'Bluewood', 'BLUEWOOD-1013801', 'ban-trang-diem-lano-btd-078', NULL, NULL, 172),
(1013058, 'Ghế phòng họp NORA GPH-015', 4590000, 'Kích thước: W564 × D600 × H835 × SH435 Quy cách: Ghế phòng họp hiện đại – tối giản, gam màu đen sang trọng, dễ phối hợp nhiều phong cách nội thất. Thiết kế rộng rãi, thoải mái, phù hợp phòng họp, đào tạo, hội thảo. Chất liệu: Tựa lưng nhựa PP dạng lưới: thông thoáng, nhẹ nhàng Mặt ngồi nhựa cao cấp: chắc chắn, hạn chế bám bẩn Trọng lượng gọn nhẹ: dễ di chuyển, sắp xếp Phong cách: Hiện đại, tối giản, chuyên nghiệp – phù hợp xu hướng văn phòng hiện đại. Ứng dụng: Phòng họp công ty, trung tâm đào tạo, không gian hội thảo, văn phòng đa năng.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-phong-hop-nora-gph-015-2.jpg', NULL, NULL, NULL, 'W564 × D600 × H835 × SH435', 'Bluewood', 'BLUEWOOD-1013058', 'ghe-phong-hop-nora-gph-015', NULL, NULL, 161),
(1000252, 'Tủ bếp MODO TBP-001', 5015000, 'Tủ bếp trên dưới Bluewood TBP-001 – Sắc trắng hiện đại là sự kết hợp tinh tế giữa thiết kế sang trọng và công năng tiện lợi. Kích thước tổng thể: Chiều cao: 2540 mm Chiều rộng: 3500 mm Chiều sâu: 670 mm', 'Tủ bếp tân cổ điển', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/tu-bep-modo-tbp-001-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'TBP-001', 'tu-bep-modo-tbp-001', NULL, NULL, 90),
(1000253, 'Tủ bếp MODO TBP-002', 5015000, 'Kích thước sản phẩm Với kích thước được thiết kế chính xác nhằm tối đa hóa công năng sử dụng, sản phẩm có: Chiều cao: 2630 mm Chiều rộng: 4846 mm Chiều sâu: 650 mm', 'Tủ bếp tân cổ điển', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/tu-bep-modo-tbp-002-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', '6806', 'tu-bep-modo-tbp-002', NULL, NULL, 90),
(1013848, 'Bàn học LANO BHC-002', 5340000, 'Kích thước: 1200 × 1650 mm – nhỏ gọn, cân đối, phù hợp nhiều không gian học tập. Quy cách: Bàn học hiện đại – thiết kế tối giản, tone vân gỗ phối trắng trẻ trung. Tích hợp kệ phía trên và nhiều hộc kéo tiện lợi. Chất liệu: MDF chống ẩm cao cấp: hạn chế cong vênh, co ngót, mối mọt. Bề mặt phủ Melamine: chống trầy nhẹ, dễ vệ sinh, giữ màu sắc bền đẹp. Kết cấu chắc chắn: ổn định khi học tập và làm việc. Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Bàn', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ban-hoc-lano-bhc-002-2.jpg', NULL, NULL, NULL, '1200 × 1650 mm – nhỏ gọn, cân đối, phù hợp nhiều không gian học tập.', 'Bluewood', 'BLUEWOOD-1013848', 'ban-hoc-lano-bhc-002', NULL, NULL, 96),
(1002737, 'Giường ngủ LUNO GNG-069', 5950000, 'Thiết kế hiện đại, tinh tế : Kiểu dáng tối giản, đầu giường nguyên tấm liền khối, hông giường dày 5cm, tông màu trang nhã. Chất liệu cao cấp : Khung giường MDF chống cong vênh, vạt và thanh đỡ bằng gỗ cao su LVL chịu lực tốt, chân chống bằng gỗ cao su/tràm bền chắc. Kết cấu vững chãi : Giường 1m6 có 12 vạt, 1 cây dọc, 4 chân chống; giường 1m8 có 12 vạt, 2 cây dọc, 8 chân chống, đảm bảo ổn định và chịu lực cao. Công năng tiện ích : Dễ lắp đặt, dễ vệ sinh, phù hợp với nhiều loại nệm, mang lại giấc ngủ thoải mái.', 'Giường ngủ', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/giuong-ngu_GNG-069_2.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GNG-069', 'giuong-ngu-luno-gng-069', NULL, NULL, 92),
(1014082, 'Ghế sofa spa SOFT GSP-002', 6500000, 'Kích thước: 170 × 90 cm – rộng rãi, phù hợp cho 2–3 người ngồi. Quy cách: Sofa băng cao cấp – thiết kế vỏ sò mềm mại, bo cong tinh tế, gam màu kem sang trọng. Phù hợp spa, thẩm mỹ viện, salon tóc, showroom mỹ phẩm, văn phòng tiếp khách. Chất liệu: Vải nhung cao cấp: mềm mại, sang trọng, giữ form tốt, dễ vệ sinh Chân sắt sơn nhũ vàng: chắc chắn, chống oxy hóa, tăng thẩm mỹ Khung ghế ổn định, bền bỉ theo thời gian Phong cách: Hiện đại – sang trọng – tinh tế. Dễ phối hợp với phong cách Luxury , Minimalism , Contemporary .', 'Sofa', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-spa-gsp-002-5.jpg', NULL, NULL, NULL, '170 × 90 cm – rộng rãi, phù hợp cho 2–3 người ngồi.', 'Bluewood', 'BLUEWOOD-1014082', 'ghe-sofa-spa-soft-gsp-002', NULL, NULL, 67),
(1013779, 'Kệ giày LANO KGY-004', 7524000, 'Kích thước: 1200 × 350 × 2200 mm – thiết kế cao kịch trần, tối ưu diện tích. Quy cách: Kệ giày đa năng – dáng đứng hiện đại, tone vân gỗ phối trắng tinh tế. Phù hợp căn hộ, nhà phố, chung cư nhỏ, phòng khách, hành lang. Chất liệu: MDF chống ẩm: hạn chế cong vênh, co ngót Bề mặt phủ Melamine: chống trầy, hạn chế bám bẩn, dễ vệ sinh Phụ kiện giảm chấn cao cấp: đóng mở êm ái, tăng tuổi thọ Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Tủ và kệ', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ke-giay-lano-kgy-004-8.jpg', NULL, NULL, NULL, '1200 × 350 × 2200 mm – thiết kế cao kịch trần, tối ưu diện tích.', 'Bluewood', 'BLUEWOOD-1013779', 'ke-giay-lano-kgy-004', NULL, NULL, 85),
(1013360, 'Ghế sofa phòng khách JUNO GSF-110', 8340000, 'Kích thước: 2105 × 830 × 635 mm Quy cách: Sofa phòng khách hiện đại – thiết kế tối giản, thanh lịch, gam màu trung tính sang trọng. Phù hợp căn hộ chung cư, nhà phố, studio, showroom nội thất, khu vực tiếp khách văn phòng. Chất liệu: Khung gỗ: Gỗ thông + plywood cao cấp, chịu lực tốt, hạn chế cong vênh Đệm ngồi: Mouse đàn hồi + gòn tấm 200gr, êm ái, hạn chế xẹp lún Chân gỗ cao su: Màu gỗ tự nhiên, sang trọng, bền đẹp Phong cách: Tối giản, hiện đại, tinh tế – dễ phối hợp nhiều phong cách nội thất như Japandi, Scandinavian, hoặc không gian gỗ tự nhiên. Ứng dụng: Phòng khách gia đình, căn hộ hiện đại, studio, showroom, khu vực tiếp khách văn phòng.', 'Sofa', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-sofa-phong-khach-juno-gsf-110-rea.jpg', NULL, NULL, NULL, '2105 × 830 × 635 mm', 'Bluewood', 'BLUEWOOD-1013360', 'ghe-sofa-phong-khach-juno-gsf-110', NULL, NULL, 67),
(1003574, 'Giường ngủ LUNO GNG-202', 8870000, 'Thiết kế hiện đại & tối giản : Đầu giường nguyên tấm liền khối, hông giường dày 5cm, chiều dài tiêu chuẩn 2m. Chất liệu cao cấp : Khung MDF chống cong vênh – mối mọt, vạt & thanh đỡ bằng gỗ cao su LVL, chân chống gỗ cao su/tràm. Cấu trúc vững chắc : Giường 1,6m có 12 vạt, 1 cây dọc, 4 chân chống; giường 1,8m có 12 vạt, 2 cây dọc, 8 chân chống. Tiện ích vượt trội : Độ bền lâu dài, nâng đỡ giấc ngủ tối ưu, dễ phối hợp với nhiều phong cách nội thất.', 'Giường ngủ', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/giuong-ngu-luno-gng-202.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GNG-202', 'giuong-ngu-luno-gng-202', NULL, NULL, 92),
(1014089, 'Ghế sofa spa SOFT GSP-003', 8900000, 'Kích thước: 170 × 90 cm – vừa vặn, phù hợp cho 2–3 người ngồi tại khu vực lễ tân. Quy cách: Sofa băng cong cao cấp – thiết kế vỏ sò cách điệu, gam màu kem sang trọng, tựa lưng cong ôm trọn. Phù hợp spa, thẩm mỹ viện, salon tóc, showroom mỹ phẩm, văn phòng tiếp khách. Chất liệu: Vải nhung cao cấp: mềm mại, sang trọng, dễ vệ sinh, hạn chế nhăn Chân sắt sơn nhũ vàng: chắc chắn, chống oxy hóa, tăng thẩm mỹ Khung ghế ổn định, bền bỉ theo thời gian Phong cách: Hiện đại – sang trọng – tinh tế. Dễ phối hợp với phong cách Luxury , Minimalism , Contemporary .', 'Sofa spa', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-spa-soft-gsp-003-1.jpg', NULL, NULL, NULL, '170 × 90 cm – vừa vặn, phù hợp cho 2–3 người ngồi tại khu vực lễ tân.', 'Bluewood', 'BLUEWOOD-1014089', 'ghe-sofa-spa-soft-gsp-003', NULL, NULL, 129),
(1013582, 'Giường ngủ LANO GNG-295', 9450000, 'Kích thước: 1200 × 2000 mm – gọn gàng, phù hợp phòng ngủ trẻ em hoặc không gian nhỏ. Quy cách: Giường ngủ hiện đại – phong cách tối giản, trẻ trung. Phù hợp phòng ngủ bé gái, phòng ngủ cá nhân, căn hộ nhỏ. Chất liệu: Khung MDF chống ẩm phủ Melamine: bền chắc, hạn chế cong vênh, dễ vệ sinh Đầu giường bọc da simili cao cấp: mềm mại, sang trọng, dễ lau chùi Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Minimalism , Modern , Scandinavian .', 'Giường ngủ trẻ em', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/giuong-ngu-lano-gng-295-1.jpg', NULL, NULL, NULL, '1200 × 2000 mm – gọn gàng, phù hợp phòng ngủ trẻ em hoặc không gian nhỏ.', 'Bluewood', 'BLUEWOOD-1013582', 'giuong-ngu-lano-gng-295', NULL, NULL, 103),
(1013753, 'Giường ngủ LANO GNG-296', 9450000, 'Kích thước: 1200 × 2000 mm – tiêu chuẩn, gọn gàng, phù hợp nhiều không gian. Quy cách: Giường ngủ hiện đại – thiết kế bo cong mềm mại, đầu giường bọc da simili. Phù hợp phòng ngủ trẻ em, phòng ngủ cá nhân, căn hộ hiện đại, homestay. Chất liệu: Khung MDF chống ẩm: ổn định, hạn chế cong vênh Bề mặt sơn PU: chống trầy, hạn chế bám bụi, dễ vệ sinh Đầu giường bọc da simili sọc dọc: mềm mại, sang trọng, bền đẹp Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Giường ngủ trẻ em', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/giuong-ngu-lano-gng-296-2.jpg', NULL, NULL, NULL, '1200 × 2000 mm – tiêu chuẩn, gọn gàng, phù hợp nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013753', 'giuong-ngu-lano-gng-296', NULL, NULL, 103),
(1013366, 'Ghế sofa phòng khách JUNO GSF-109', 9660000, 'Kích thước: Dài 2003 mm × Rộng 830 mm × Cao 650 mm Quy cách: Sofa phòng khách phong cách tối giản – gam màu kem trang nhã, kiểu dáng mềm mại, bo cong tinh tế. Phù hợp căn hộ chung cư, nhà phố hiện đại, studio, homestay, showroom nội thất. Chất liệu: Khung sofa: Gỗ thông tự nhiên + plywood cao cấp, chịu lực tốt, hạn chế cong vênh Đệm ngồi: Mouse đàn hồi + gòn tấm 200gr, êm ái, giữ form lâu dài Chân gỗ cao su tự nhiên: chắc chắn, màu gỗ tự nhiên sang trọng Phong cách: Tối giản, hiện đại, mang hơi hướng Scandinavian và Japandi – dễ phối hợp với nhiều phong cách nội thất khác nhau.', 'Sofa phòng khách', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-sofa-phong-khach-juno-gsf-109-5.jpg', NULL, NULL, NULL, 'Dài 2003 mm × Rộng 830 mm × Cao 650 mm', 'Bluewood', 'BLUEWOOD-1013366', 'ghe-sofa-phong-khach-juno-gsf-109', NULL, NULL, 133),
(1002115, 'Giường ô tô LINA GTO-032', 9900000, 'Thiết kế mô phỏng xe Lightning McQueen với đầu giường liền khối, tạo cảm giác vui nhộn và kích thích trí tưởng tượng của bé. Khung giường làm từ ván MDF chống ẩm, vạt giường gỗ cao su LVL chịu lực tốt, chân chống giữa bằng gỗ tự nhiên, đảm bảo độ bền và an toàn. Khoang chứa đồ ẩn dưới giường giúp tối ưu diện tích phòng, thuận tiện cất giữ đồ chơi và sách vở. Màu xanh dương tươi sáng, dễ phối hợp với nội thất phòng trẻ em hiện đại. Dễ tháo lắp, vệ sinh thuận tiện, phù hợp cho bé từ 3–12 tuổi, hỗ trợ giấc ngủ ngon và phát triển trí tưởng tượng.', 'Giường ô tô', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gto-032-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GTO-032', 'giuong-o-to-lina-gto-032', NULL, NULL, 106),
(1014071, 'Ghế sofa spa SOFT GSP-001', 9950000, 'Kích thước: dài 1.8 m – phù hợp cho 3–4 người ngồi, cân đối cho khu vực lễ tân. Quy cách: Sofa cong cao cấp – gam màu kem thanh lịch, bọc vải nhung mềm mại, đi kèm 03 gối tròn đồng bộ. Phù hợp spa, thẩm mỹ viện, salon, showroom, khách sạn boutique. Chất liệu: Vải nhung cao cấp: mềm mại, sang trọng, dễ vệ sinh, bền màu Khung sofa chắc chắn: ổn định, bền bỉ Gối tròn đồng bộ: tăng thẩm mỹ và tiện nghi Phong cách: Hiện đại – sang trọng – tinh tế. Dễ phối hợp với phong cách Luxury , Minimalism , Contemporary .', 'Sofa', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-spa-gsp-001-2.jpg', NULL, NULL, NULL, 'dài 1.8 m – phù hợp cho 3–4 người ngồi, cân đối cho khu vực lễ tân.', 'Bluewood', 'BLUEWOOD-1014071', 'ghe-sofa-spa-soft-gsp-001', NULL, NULL, 67),
(1013727, 'Ghế sofa phòng khách LINA GSF-112', 10150000, 'Kích thước: Dài 2400 mm – rộng rãi, thoải mái cho cả gia đình. Quy cách: Sofa băng dài – thiết kế hiện đại, sang trọng. Phù hợp phòng khách căn hộ cao cấp, nhà phố, biệt thự, lounge, phòng tiếp khách. Chất liệu: Khung gỗ tự nhiên: chắc chắn, chịu lực tốt, hạn chế cong vênh Đệm mút HR40 cao cấp: đàn hồi tốt, hạn chế xẹp lún, ngồi lâu thoải mái Bọc da Microfiber: mềm mịn như da thật, dễ vệ sinh, bền đẹp Chân sofa thanh mảnh: hiện đại, thoáng, dễ lau chùi bên dưới Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Contemporary , Minimalism , Scandinavian , Modern .', 'Sofa băng', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-phong-khach-lina-gsf-112-replace.jpg', NULL, NULL, NULL, 'Dài 2400 mm – rộng rãi, thoải mái cho cả gia đình.', 'Bluewood', 'BLUEWOOD-1013727', 'ghe-sofa-phong-khach-lina-gsf-112', NULL, NULL, 112),
(1012558, 'Ghế sofa băng LUNO GSF-108', 10590000, 'Kích thước: 2000 × 820 × 800 mm (dáng dài 3 chỗ ngồi) Quy cách: Sofa hiện đại – tối giản, tone xám trung tính, form vuông vức sang trọng, tay vịn bo cong nhẹ, chân cao thoáng thanh mảnh. Chất liệu: Khung gỗ thông kết hợp Plywood chắc chắn, chịu lực tốt Đệm mousse đàn hồi cao, êm ái, hạn chế xẹp lún Lớp gòn tấm 200gr tăng độ mềm mại, giữ form lâu dài Chân gỗ cao su tự nhiên, bền chắc, chống mối mọt Phong cách: Hiện đại, Minimalist, Scandinavian, trung tính – dễ phối hợp nhiều không gian. Công năng: Ngồi thoải mái cho 3 người, phù hợp cả ngồi và nằm nghỉ Tựa lưng êm ái, nâng đỡ tốt Gầm ghế cao, dễ vệ sinh, thích hợp robot hút bụi Ứng dụng: Phòng khách căn hộ, nhà phố, không gian vừa – lớn, tiếp khách, nghỉ ngơi, thư giãn hằng ngày.', 'Sofa băng', 1, 'https://bluewood.vn/wp-content/uploads/2026/04/ghe-sofa-neo-gsf-108-2.jpg', NULL, NULL, NULL, '2000 × 820 × 800 mm (dáng dài 3 chỗ ngồi)', 'Bluewood', 'BLUEWOOD-1012558', 'ghe-sofa-bang-luno-gsf-108', NULL, NULL, 112),
(1013839, 'Tủ quần áo LANO TAO-034', 10620000, 'Kích thước: 1800 × 600 × 2000 mm – tiêu chuẩn, phù hợp phòng ngủ chung cư và nhà phố. Quy cách: Tủ quần áo hiện đại – tone trắng phối vân gỗ sang trọng, tay nắm âm tinh tế, nhiều khoang lưu trữ khoa học. Chất liệu: MDF chống ẩm phủ sơn PU: bền đẹp, chống cong vênh, chống ẩm, dễ vệ sinh Phụ kiện giảm chấn cao cấp: đóng mở êm ái, hạn chế tiếng ồn, tăng tuổi thọ Phong cách: Hiện đại – tối giản – tinh tế. Dễ phối hợp với phong cách Minimalism , Modern , Contemporary .', 'Tủ và kệ', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/tu-quan-ao-lano-tao-034-5.jpg', NULL, NULL, NULL, '1800 × 600 × 2000 mm – tiêu chuẩn, phù hợp phòng ngủ chung cư và nhà phố.', 'Bluewood', 'BLUEWOOD-1013839', 'tu-quan-ao-lano-tao-034', NULL, NULL, 85),
(1014031, 'Bộ bàn ăn CASO BBA-123', 12530000, 'Kích thước: 1400 × 780 × 740 mm – gọn gàng, phù hợp gia đình 4 người. Quy cách: Bộ bàn ăn hiện đại – gồm 1 bàn + 4 ghế. Mặt bàn đá ceramic vân mây sang trọng, chân inox mạ sáng bóng, ghế da PU thanh lịch. Chất liệu: Mặt bàn đá ceramic: chống trầy, chịu nhiệt, chống thấm, dễ vệ sinh, bền đẹp Chân bàn inox mạ: sáng bóng, chống oxy hóa, chịu lực tốt Ghế da PU: mềm mại, dễ vệ sinh, chống bong tróc Chân ghế sắt sơn tĩnh điện: chắc chắn, ổn định Phong cách: Hiện đại – tối giản – sang trọng. Dễ phối hợp với phong cách Modern , Luxury , Minimalism , Scandinavian .', 'Bộ bàn ghế', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/bo-ban-an-caso-bba-123-7.jpg', NULL, NULL, NULL, '1400 × 780 × 740 mm – gọn gàng, phù hợp gia đình 4 người.', 'Bluewood', 'BLUEWOOD-1014031', 'bo-ban-an-caso-bba-123', NULL, NULL, 83),
(1013759, 'Tủ Quần Áo LANO TAO-033', 13140000, 'Kích thước: 1800 × 600 × 2000 mm – tiêu chuẩn, dễ bố trí nhiều không gian. Quy cách: Tủ quần áo hiện đại – thiết kế dáng đứng, bo cong mềm mại. Phù hợp phòng ngủ trẻ em, căn hộ hiện đại, nhà phố, phong cách Bắc Âu. Chất liệu: MDF chống ẩm: ổn định, hạn chế cong vênh, phù hợp khí hậu nóng ẩm Bề mặt phủ sơn PU: mịn đẹp, chống trầy, dễ vệ sinh Phụ kiện giảm chấn: đóng mở êm ái, hạn chế tiếng ồn, tăng tuổi thọ Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Scandinavian , Modern , Minimalism .', 'Tủ và kệ', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/tu-quan-ao-lano-tao-033-1.jpg', NULL, NULL, NULL, '1800 × 600 × 2000 mm – tiêu chuẩn, dễ bố trí nhiều không gian.', 'Bluewood', 'BLUEWOOD-1013759', 'tu-quan-ao-lano-tao-033', NULL, NULL, 85),
(1013829, 'Tủ quần áo LANO TAO-035', 13140000, 'Kích thước: 1800 × 600 × 2000 mm – tiêu chuẩn, phù hợp phòng ngủ vừa và nhỏ. Quy cách: Tủ quần áo hiện đại – thiết kế cửa lùa tiện lợi, tone hồng phối trắng trẻ trung. Phù hợp phòng ngủ bé gái, căn hộ hiện đại, phong cách Hàn Quốc. Chất liệu: MDF chống ẩm cao cấp: hạn chế cong vênh, mối mọt Bề mặt phủ sơn PU: nhẵn mịn, chống trầy, dễ vệ sinh Phụ kiện giảm chấn: đóng mở êm ái, hạn chế tiếng ồn, tăng độ bền Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Korean , Modern , Minimalism , Scandinavian .', 'Tủ và kệ', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/tu-quan-ao-lano-tao-035-7.jpg', NULL, NULL, NULL, '1800 × 600 × 2000 mm – tiêu chuẩn, phù hợp phòng ngủ vừa và nhỏ.', 'Bluewood', 'BLUEWOOD-1013829', 'tu-quan-ao-lano-tao-035', NULL, NULL, 85),
(1013736, 'Ghế sofa phòng khách LINA GSF-113', 13790000, 'Kích thước: Dài 2800 mm – rộng rãi, thoải mái cho nhiều người cùng lúc. Quy cách: Sofa băng dài – thiết kế bề thế, sang trọng. Phù hợp phòng khách biệt thự, căn hộ cao cấp, nhà phố hiện đại, lounge, phòng tiếp khách. Chất liệu: Khung gỗ tự nhiên: chắc chắn, chịu lực tốt, hạn chế cong vênh Nệm mút HR40 cao cấp: đàn hồi tốt, hạn chế xẹp lún, ngồi lâu thoải mái Bọc da Microfiber: mềm mại, sang trọng, dễ vệ sinh, bền đẹp Gối tựa đi kèm: tăng sự thoải mái, tiện dụng Phong cách: Hiện đại – sang trọng – đẳng cấp. Dễ phối hợp với phong cách Luxury , Contemporary , Minimalism , Modern .', 'Sofa băng', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-sofa-phong-khach-lina-gsf-113-1-2.jpg', NULL, NULL, NULL, 'Dài 2800 mm – rộng rãi, thoải mái cho nhiều người cùng lúc.', 'Bluewood', 'BLUEWOOD-1013736', 'ghe-sofa-phong-khach-lina-gsf-113', NULL, NULL, 112),
(1010532, 'Bộ bàn ăn CASO BBA-095', 13950000, 'Kích thước bàn: Tiêu chuẩn cho 4–6 người, tối ưu không gian phòng ăn (Dài ~1200mm × Rộng ~700mm × Cao ~750mm) Quy cách: Bộ bàn ăn hiện đại phong cách châu Âu, mặt bàn đá Ceramic bóng sang trọng, chân bàn inox mạ PVD cách điệu tạo điểm nhấn, ghế ăn đồng bộ bọc da PU mềm mại Chất liệu: Mặt bàn: Đá Ceramic bóng cao cấp, chịu lực – chịu nhiệt tốt, chống thấm, chống ố, dễ vệ sinh Chân bàn: Inox mạ PVD chống oxy hóa, hạn chế trầy xước, giữ màu bền đẹp Ghế: Đệm mút bọc da PU cao cấp, êm ái, dễ lau chùi, ít bám bẩn Màu sắc: Tông màu trung tính, ánh kim sang trọng, dễ phối hợp với nhiều phong cách nội thất Phong cách: Hiện đại, tinh tế, sang trọng, pha nét châu Âu Công năng: Bàn ăn gia đình, bàn tiếp khách, bàn sinh hoạt chung, phù hợp cho căn hộ cao cấp, nhà phố hiện đại, biệt thự sang trọng Ứng dụng: Phòng ăn chung cư, nhà phố, biệt thự, không gian sống cao cấp', 'Bộ bàn ghế', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/bo-ban-an-caso-bba-095-8.jpg', NULL, NULL, 'Tông màu trung tính, ánh kim sang trọng, dễ phối hợp với nhiều phong cách nội thất', NULL, 'Bluewood', 'BBA-095', 'bo-ban-an-caso-bba-095', NULL, NULL, 83),
(1014022, 'Bộ bàn ăn CASO BBA-122', 19470000, 'Kích thước: 1800 × 900 × 740 mm – rộng rãi, phù hợp gia đình 6–8 người. Quy cách: Bộ bàn ăn cao cấp – gồm 1 bàn + 8 ghế. Mặt bàn đá vi tinh thể sang trọng, chân inox mạ cao cấp, ghế bọc da PU êm ái. Chất liệu: Mặt bàn đá vi tinh thể: chống trầy, chịu nhiệt, chống thấm, dễ vệ sinh, bền đẹp Chân bàn inox mạ: chống oxy hóa, hạn chế han gỉ, kết cấu vững chắc Ghế da PU: mềm mại, chống bong tróc, dễ vệ sinh Chân ghế sắt sơn tĩnh điện: bền chắc, ổn định Phong cách: Hiện đại – sang trọng – luxury. Dễ phối hợp với phong cách Contemporary , Modern , Luxury .', 'Bộ bàn ghế', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/bo-ban-an-caso-bba-122-8.jpg', NULL, NULL, NULL, '1800 × 900 × 740 mm – rộng rãi, phù hợp gia đình 6–8 người.', 'Bluewood', 'BLUEWOOD-1014022', 'bo-ban-an-caso-bba-122', NULL, NULL, 83),
(1013574, 'Giường tầng LANO GTG-025', 25000000, 'Kích thước: Dài: 2682 mm Cao: 2700 mm Sâu: 1282 mm Quy cách: Giường tầng hiện đại – phối màu xanh pastel và hồng nhẹ nhàng. Phù hợp phòng ngủ trẻ em, căn hộ hiện đại, nhà phố diện tích vừa và nhỏ. Chất liệu: MDF chống ẩm cao cấp: hạn chế cong vênh, mối mọt Bề mặt phủ sơn PU: màu sắc bền đẹp, chống trầy nhẹ, dễ vệ sinh Phong cách: Hiện đại – tối giản – trẻ trung. Dễ phối hợp với phong cách Modern , Minimalism .', 'Giường gỗ công nghiệp', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/giuong-tang-lano-gtg-025-7.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'BLUEWOOD-1013574', 'giuong-tang-lano-gtg-025', NULL, NULL, 156),
(1003844, 'Ghế phòng họp NEO GPH-007', 420000, 'Thiết kế tối giản, chuyên nghiệp : Kích thước phù hợp vóc dáng người Việt, lưng lưới thoáng khí, đệm ngồi êm ái. Chất liệu cao cấp, bền bỉ : Khung sắt mạ inox chống gỉ, lưng lưới đàn hồi tốt, đệm mút nguyên khối chống xẹp. Công thái học hỗ trợ sức khỏe : Giúp giảm mỏi lưng, tăng sự tập trung trong công việc. Tiện lợi khi sử dụng : Trọng lượng nhẹ, dễ di chuyển và bố trí trong nhiều không gian. Ứng dụng đa dạng : Phù hợp cho phòng họp, tiếp khách, văn phòng hoặc sử dụng tại gia đình.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-007.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-007', 'ghe-phong-hop-neo-gph-007', NULL, NULL, 161),
(1010962, 'Ghế cafe DAILY GCF-018', 459000, 'Kích thước ghế: Cao tổng thể 465mm × Rộng 380mm × Sâu 380mm × Cao mặt ngồi 455mm Quy cách: Ghế nhựa PP liền khối phong cách hiện đại – tối giản, mặt ngồi vuông gọn bo nhẹ, chân vát nhẹ tăng độ ổn định, có khả năng xếp chồng tiện lợi Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống ẩm, chống cong vênh Bề mặt: Phẳng, nhẵn mịn, dễ lau chùi, không thấm nước Màu sắc: Trẻ trung, đa dạng, dễ phối hợp theo concept quán, tạo điểm nhấn nổi bật Phong cách: Hiện đại, tối giản, năng động Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, quán ăn nhanh, phòng ăn gia đình, ban công, sân thượng có mái che, studio sáng tạo Ứng dụng: Quán cafe, quán trà sữa, nhà hàng, khu ẩm thực, không gian ngoài trời có mái che, phòng ăn gia đình, không gian làm việc sáng tạo', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-018-9.jpg', NULL, NULL, 'Trẻ trung, đa dạng, dễ phối hợp theo concept quán, tạo điểm nhấn nổi bật', 'Cao tổng thể 465mm × Rộng 380mm × Sâu 380mm × Cao mặt ngồi 455mm', 'Bluewood', 'GCF-018', 'ghe-cafe-daily-gcf-018', NULL, NULL, 163),
(1003841, 'Ghế phòng họp NEO GPH-004', 486000, 'Thiết kế tối giản nhưng sang trọng, dễ hòa nhập với nhiều phong cách nội thất phòng họp Kích thước tối ưu (55 x 48 x 93 cm), mang lại sự thoải mái khi ngồi lâu Khung thép mạ crom sáng bóng, chắc chắn, chống gỉ sét và bền bỉ theo thời gian Lưng ghế lưới thoáng khí, đệm ngồi vải cao cấp êm ái, chống xẹp lún Tay vịn cố định chắc chắn, bọc nhựa hoặc PU, hỗ trợ giảm áp lực cho vai và tay Chân quỳ vững chãi, dễ bố trí và di chuyển linh hoạt trong nhiều không gian', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-004.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-004', 'ghe-phong-hop-neo-gph-004', NULL, NULL, 161),
(1003843, 'Ghế phòng họp NEO GPH-006', 486000, 'Kích thước hợp lý : W510 x D490 x H940 mm, đảm bảo sự thoải mái trong các cuộc họp dài. Thiết kế tối giản, hiện đại : Kiểu dáng thanh lịch, dễ phối hợp với nhiều phong cách nội thất. Chất liệu cao cấp : Khung thép mạ crom sáng bóng, chống gỉ sét; lưng và đệm bằng lưới thoáng khí. Độ bền vượt trội : Khả năng chịu lực tốt, chống cong vênh, tuổi thọ sử dụng lâu dài. Tiện ích và thẩm mỹ : Mang lại sự thoải mái, dễ dàng kết hợp với bàn họp, nâng tầm không gian chuyên nghiệp.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-006.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-006', 'ghe-phong-hop-neo-gph-006', NULL, NULL, 161),
(1000485, 'Ghế văn phòng NEO GVP-001', 490000, 'Kích thước: Rộng 480mm × Sâu 500mm × Cao tổng 970mm Quy cách: Ghế văn phòng hiện đại, lưng lưới thoáng khí cong nhẹ hỗ trợ cột sống, đệm ngồi mút đúc nguyên khối bọc vải/da tổng hợp, tay vịn công thái học, chân xoay kim loại mạ chrome với bánh xe PU xoay 360° Chất liệu: Lưng lưới polyester cao cấp, đệm mút đàn hồi bọc vải hoặc da tổng hợp, khung nhựa chịu lực/kim loại chắc chắn, chân kim loại mạ chrome, bánh xe PU chống trầy sàn Màu sắc: Tông màu hiện đại, dễ phối hợp (đen, xám, hoặc tùy chọn theo yêu cầu) Phong cách: Hiện đại, tinh tế, chuyên nghiệp Công năng: Điều chỉnh độ cao linh hoạt, xoay 360°, di chuyển êm ái, hỗ trợ tư thế ngồi chuẩn, giảm mỏi khi ngồi lâu Ứng dụng: Ghế văn phòng công ty, ghế phòng họp, ghế làm việc tại nhà', 'Phòng làm việc', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-van-phong-neo-gvp-001-reup-1.jpg', NULL, 'Lưng lưới polyester cao cấp, đệm mút đàn hồi bọc vải hoặc da tổng hợp, khung nhựa chịu lực/kim loại chắc chắn, chân kim loại mạ chrome, bánh xe PU chống trầy sàn', 'Tông màu hiện đại, dễ phối hợp (đen, xám, hoặc tùy chọn theo yêu cầu)', 'Rộng 480mm × Sâu 500mm × Cao tổng 970mm', 'Bluewood', 'GVP-001', 'ghe-van-phong-neo-gvp-001', NULL, NULL, 99),
(1010999, 'Ghế cafe DAILY GCF-021', 490000, 'Kích thước ghế: Cao tổng thể 800mm × Rộng 465mm × Sâu 550mm × Cao mặt ngồi 460mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế cong nhẹ ôm dáng, mặt ngồi rộng vừa phải, chân ghế chắc chắn tạo độ ổn định cao Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống biến dạng, nhẹ và dễ di chuyển Bề mặt: Nhẵn mịn, dễ lau chùi, hạn chế phai màu Màu sắc: Đa dạng (trung tính và nổi bật), dễ phối hợp với nhiều phong cách nội thất Phong cách: Hiện đại, tối giản, trẻ trung, tinh tế Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, văn phòng, phòng họp nhỏ, showroom, khu vực tiếp khách Ứng dụng: Quán cafe, nhà hàng, văn phòng sáng tạo, phòng ăn gia đình, khu vực chờ – tiếp khách, không gian sinh hoạt chung', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-021-11.jpg', NULL, NULL, 'Đa dạng (trung tính và nổi bật), dễ phối hợp với nhiều phong cách nội thất', 'Cao tổng thể 800mm × Rộng 465mm × Sâu 550mm × Cao mặt ngồi 460mm', 'Bluewood', 'GCF-021', 'ghe-cafe-daily-gcf-021', NULL, NULL, 163),
(1011093, 'Ghế cafe DAILY GCF-017', 490000, 'Kích thước ghế: Cao tổng thể 900mm × Rộng 400mm × Sâu 400mm × Cao mặt ngồi 445mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế cao với các thanh dọc thoáng khí, mặt ngồi phẳng rộng vừa đủ, khung ghế chắc chắn có thanh giằng tăng độ ổn định Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống ẩm, chống cong vênh Bề mặt: Nhẵn mịn, dễ lau chùi, không thấm nước Màu sắc: Đa dạng, nổi bật, dễ phối hợp với nhiều phong cách nội thất (tối giản, trẻ trung, năng động) Phong cách: Hiện đại, tối giản, thanh lịch Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, khu ăn uống ngoài trời, sân vườn, ban công, hồ bơi, phòng ăn gia đình, sự kiện hoặc hội trường Ứng dụng: Quán cafe, nhà hàng, phòng ăn gia đình, không gian ngoài trời có mái che, khu vực chờ – tiếp khách, hội trường', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-017-10.jpg', NULL, NULL, 'Đa dạng, nổi bật, dễ phối hợp với nhiều phong cách nội thất (tối giản, trẻ trung, năng động)', 'Cao tổng thể 900mm × Rộng 400mm × Sâu 400mm × Cao mặt ngồi 445mm', 'Bluewood', 'GCF-017', 'ghe-cafe-daily-gcf-017', NULL, NULL, 163),
(1011193, 'Ghế cafe DAILY GCF-029', 490000, 'Kích thước ghế: Cao tổng thể 785mm × Rộng 512mm × Sâu 560mm × Cao mặt ngồi 450mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế họa tiết đan xen độc đáo, bo tròn mềm mại, mặt ngồi rộng rãi, chân ghế chắc chắn tạo độ ổn định cao Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống ẩm, chống nước, chống biến dạng Bề mặt: Nhẵn mịn, dễ lau chùi, vệ sinh nhanh chóng Màu sắc: Đa dạng, trẻ trung, dễ phối hợp với nhiều phong cách nội thất (hiện đại, tối giản, trẻ trung năng động) Phong cách: Hiện đại, tối giản, tinh tế Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, văn phòng, khu vực tiếp khách, sân vườn, ban công, sự kiện Ứng dụng: Quán cafe, nhà hàng, phòng ăn gia đình, văn phòng sáng tạo, khu vực chờ – tiếp khách, không gian ngoài trời có mái che', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-029-2.jpg', NULL, NULL, 'Đa dạng, trẻ trung, dễ phối hợp với nhiều phong cách nội thất (hiện đại, tối giản, trẻ trung năng động)', 'Cao tổng thể 785mm × Rộng 512mm × Sâu 560mm × Cao mặt ngồi 450mm', 'Bluewood', 'GCF-029', 'ghe-cafe-daily-gcf-029', NULL, NULL, 163),
(1011204, 'Ghế cafe DAILY GCF-030', 490000, 'Kích thước ghế: Cao tổng thể 785mm × Rộng 512mm × Sâu 560mm × Cao mặt ngồi 450mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế cong ôm sát cơ thể, tay vịn liền khối chắc chắn, chân ghế vững chắc phân bổ lực đều, có khả năng xếp chồng tiện lợi Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống thấm nước, chống biến dạng Bề mặt: Nhẵn mịn, dễ lau chùi, vệ sinh nhanh chóng Màu sắc: Đa dạng, trẻ trung, dễ phối hợp với nhiều phong cách nội thất (hiện đại, tối giản, trẻ trung năng động) Phong cách: Hiện đại, tối giản, tinh tế Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, văn phòng, khu vực tiếp khách, sân vườn, ban công, không gian ngoài trời Ứng dụng: Quán cafe, nhà hàng, phòng ăn gia đình, văn phòng sáng tạo, khu vực chờ – tiếp khách, không gian ngoài trời có mái che', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-030-3-1.jpg', NULL, NULL, 'Đa dạng, trẻ trung, dễ phối hợp với nhiều phong cách nội thất (hiện đại, tối giản, trẻ trung năng động)', 'Cao tổng thể 785mm × Rộng 512mm × Sâu 560mm × Cao mặt ngồi 450mm', 'Bluewood', 'GCF-030', 'ghe-cafe-daily-gcf-030', NULL, NULL, 163),
(1003845, 'Ghế phòng họp LUNO GPH-008', 540000, 'Thiết kế hiện đại, tinh tế : Kích thước tiêu chuẩn 50 x 47 x 90cm, kiểu dáng thanh lịch, dễ hòa hợp nội thất. Chất liệu cao cấp, bền bỉ : Khung sắt mạ crom sáng bóng, chống gỉ sét và ăn mòn; lưng tựa, đệm ngồi bằng lưới/vải cao cấp. Chân quỳ vững chắc : Mang lại sự ổn định, chắc chắn và dễ dàng di chuyển, sắp xếp linh hoạt. Công thái học hỗ trợ sức khỏe : Giúp giảm mệt mỏi, duy trì tư thế ngồi đúng, tăng hiệu quả làm việc. Tiện ích vượt trội : Dễ vệ sinh, trọng lượng vừa phải, phù hợp cho nhiều không gian phòng họp lớn nhỏ.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-luno-gph-008.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-008', 'ghe-phong-hop-luno-gph-008', NULL, NULL, 161),
(1010842, 'Ghế cafe DAILY GCF-010', 550000, 'Kích thước ghế: Cao tổng thể 815mm × Rộng 500mm × Sâu 450mm × Cao mặt ngồi 450mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế cong ôm lưng, mặt ghế và lưng ghế có lỗ thông thoáng, kiểu dáng gọn gàng dễ phối hợp với nhiều loại bàn cafe Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, bền bỉ, hạn chế cong vênh và nứt gãy Bề mặt: Nhẵn mịn, dễ lau chùi, thoáng khí nhờ thiết kế lỗ thông thoáng Màu sắc: Đa dạng từ gam trung tính đến màu nổi bật, dễ phối hợp theo concept quán, tạo điểm nhấn sinh động Phong cách: Hiện đại, tối giản, tinh tế Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, quán ăn nhanh, văn phòng sáng tạo, không gian gia đình Ứng dụng: Quán cafe, trà sữa, nhà hàng trẻ trung, coworking space, ban công, sân vườn có mái che, căn hộ chung cư', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-010-15.jpg', NULL, NULL, 'Đa dạng từ gam trung tính đến màu nổi bật, dễ phối hợp theo concept quán, tạo điểm nhấn sinh động', 'Cao tổng thể 815mm × Rộng 500mm × Sâu 450mm × Cao mặt ngồi 450mm', 'Bluewood', 'GCF-010', 'ghe-cafe-daily-gcf-010', NULL, NULL, 163),
(1013091, 'Ghế văn phòng NEO GVP-007', 585000, 'Kích thước: 49 × 50 × 87–97 cm Quy cách: Ghế văn phòng hiện đại – thiết kế trẻ trung, lưng lưới đỏ nổi bật phối đen sang trọng. Kiểu dáng nhỏ gọn, dễ bố trí nhiều không gian làm việc. Chất liệu: Tựa lưng nhựa PP kết hợp lưới thoáng khí: hạn chế tích nhiệt, hỗ trợ lưng dưới Đệm ngồi 3 tầng bọc lưới: đàn hồi tốt, ngồi êm ái lâu dài Tay vịn PP cong uốn liền khối: chắc chắn, thẩm mỹ Chân sao mạ crom sáng bóng: chịu lực tốt, chống gỉ sét Bánh xe xoay 360°: di chuyển linh hoạt Phong cách: Hiện đại, nổi bật, trẻ trung – phù hợp văn phòng năng động, startup, học tập tại nhà. Ứng dụng: Văn phòng công ty, bàn làm việc cá nhân, phòng học tập, không gian coworking, startup.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-007-1.jpg', NULL, NULL, NULL, '49 × 50 × 87–97 cm', 'Bluewood', 'BLUEWOOD-1013091', 'ghe-van-phong-neo-gvp-007', NULL, NULL, 161),
