(1001626, 'Ghế ăn LUNO GAN-010', 896000, 'Kích thước: Rộng 450mm, sâu 500mm, cao 860mm, chiều cao mặt ngồi 460mm Quy cách: Ghế ăn hiện đại, lưng ghế may ngang tạo ô chữ nhật, form ôm sát cơ thể, chân thép sơn tĩnh điện vát chéo thanh thoát Chất liệu: Bọc da PU cao cấp, khung gỗ tự nhiên chắc chắn, chân thép sơn tĩnh điện màu đen, nệm mút đàn hồi cao Màu sắc: Kem nhẹ nhàng, Xám thanh lịch, Cam đất cá tính (hoặc tùy chọn theo yêu cầu) Phong cách: Hiện đại, tối giản, thanh lịch Ứng dụng: Ghế ăn, ghế cafe, ghế làm việc, ghế tiếp khách', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/1_GAN-010.jpg', NULL, 'Bọc da PU cao cấp, khung gỗ tự nhiên chắc chắn, chân thép sơn tĩnh điện màu đen, nệm mút đàn hồi cao', 'Kem nhẹ nhàng, Xám thanh lịch, Cam đất cá tính (hoặc tùy chọn theo yêu cầu)', 'Rộng 450mm, sâu 500mm, cao 860mm, chiều cao mặt ngồi 460mm', 'Bluewood', 'GAN-010', 'ghe-an-luno-gan-010', NULL, NULL, 162),
(1003840, 'Ghế phòng họp NEO GPH-003', 900000, 'Thiết kế sang trọng, hiện đại với tông màu đen thanh lịch, dễ phối hợp nội thất Khung thép mạ crom chắc chắn, chống gỉ sét, sáng bóng và bền bỉ theo thời gian Tựa lưng cao ôm sát cơ thể, đệm ngồi dày bọc da hoặc simili cao cấp, mang lại sự thoải mái tối đa Tay vịn cố định vừa tầm, tạo điểm tựa vững chắc, giảm áp lực cho vai và cổ Chân ghế dạng quỳ ổn định, dễ bố trí và di chuyển trong nhiều không gian phòng họp', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-003.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-003', 'ghe-phong-hop-neo-gph-003', NULL, NULL, 161),
(1003870, 'Ghế phòng họp NEO GPH-010', 900000, 'Thiết kế thanh lịch, chuyên nghiệp : Kích thước 108 x 48 x 50 cm, lưng lưới thoáng khí, đệm ngồi êm ái. Chất liệu cao cấp : Khung sắt mạ crom sáng bóng, chống gỉ sét; đệm mút đàn hồi bọc vải hoặc da PU. Công thái học hỗ trợ sức khỏe : Giúp duy trì tư thế ngồi đúng, giảm áp lực và mệt mỏi khi họp dài. Tiện ích vượt trội : Trọng lượng vừa phải, dễ di chuyển, chân tĩnh vững chắc, dễ vệ sinh. Thẩm mỹ và linh hoạt : Tông màu trung tính, dễ phối hợp với nhiều phong cách nội thất phòng họp và văn phòng.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-010.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-010', 'ghe-phong-hop-neo-gph-010', NULL, NULL, 161),
(1003839, 'Ghế phòng họp NEO GPH-001', 905000, 'Thiết kế hiện đại, tối giản, dễ bố trí trong nhiều không gian phòng họp Khung thép mạ crom chắc chắn, bền bỉ, chống gỉ sét và dễ vệ sinh Lưng ghế bằng vải lưới thoáng khí, đệm ngồi êm ái bọc vải nỉ hoặc da PU Tay vịn cố định vừa tầm, hỗ trợ giảm căng thẳng cho vai và cánh tay Chân quỳ vững chãi, ổn định và linh hoạt khi di chuyển trong không gian nhỏ', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-001.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-001', 'ghe-phong-hop-neo-gph-001', NULL, NULL, 161),
(1010861, 'Ghế cafe DAILY GCF-012', 925000, 'Kích thước ghế: Cao tổng thể 830mm × Rộng 425mm × Sâu 460mm × Cao mặt ngồi 470mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế liền khối uốn cong nhẹ ôm lưng, họa tiết đan chéo tạo thông thoáng, 4 chân thon gọn tiết kiệm diện tích Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, bền bỉ, chống cong vênh Bề mặt: Nhẵn mịn, dễ lau chùi, không bị ảnh hưởng bởi độ ẩm Màu sắc: Đa dạng với các gam trẻ trung như xanh pastel, vàng, hồng; dễ phối hợp theo concept quán, tạo điểm nhấn nổi bật Phong cách: Hiện đại, tối giản, Scandinavian, trẻ trung Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, tiệm bánh, phòng ăn gia đình, ban công, sân vườn có mái che, khu vực chờ – tiếp khách văn phòng Ứng dụng: Quán cafe, quán trà sữa, nhà hàng, văn phòng sáng tạo, phòng ăn gia đình, không gian ngoài trời có mái che', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-012-7.jpg', NULL, NULL, 'Đa dạng với các gam trẻ trung như xanh pastel, vàng, hồng; dễ phối hợp theo concept quán, tạo điểm nhấn nổi bật', 'Cao tổng thể 830mm × Rộng 425mm × Sâu 460mm × Cao mặt ngồi 470mm', 'Bluewood', 'GCF-012', 'ghe-cafe-daily-gcf-012', NULL, NULL, 163),
(1001560, 'Ghế ăn LUNO GAN-036', 935000, 'Kích thước: Cao tổng ~930mm, cao tựa lưng ~620mm, rộng ~480mm (kích thước tiết kiệm không gian) Quy cách: Ghế ăn tối giản, tựa lưng bo cong ôm sát cơ thể, form dáng gọn gàng, đường may tinh tế Chất liệu: Vải bố cao cấp thoáng khí, khung chân gỗ tự nhiên chắc chắn, nhập khẩu nguyên chiếc, gia công tinh xảo Màu sắc: Kem thanh lịch, Cam trẻ trung, Xám đậm hiện đại Phong cách: Hiện đại, tối giản, thanh thoát Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, lounge, phòng tiếp khách', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-036-3.jpg', NULL, 'Vải bố cao cấp thoáng khí, khung chân gỗ tự nhiên chắc chắn, nhập khẩu nguyên chiếc, gia công tinh xảo', 'Kem thanh lịch, Cam trẻ trung, Xám đậm hiện đại', 'Cao tổng ~930mm, cao tựa lưng ~620mm, rộng ~480mm (kích thước tiết kiệm không gian)', 'Bluewood', 'GAN-036', 'ghe-an-luno-gan-036', NULL, NULL, 162),
(1010757, 'Ghế cafe DAILY GCF-008', 935000, 'Kích thước ghế: Cao tổng thể 760mm × Rộng 600mm × Sâu 560mm Quy cách: Ghế nhựa PP liền khối phong cách tối giản – hiện đại, lưng tựa bo cong nhẹ ôm dáng, tích hợp nệm ngồi êm ái, kiểu dáng gọn gàng dễ phối hợp với nhiều loại bàn cafe Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống cong vênh, dễ vệ sinh Nệm ngồi: Tích hợp sẵn, mềm mại, tăng sự thoải mái khi ngồi lâu Màu sắc: Đa dạng từ gam trung tính đến pastel trẻ trung, dễ phối hợp theo concept quán, tạo không gian sinh động nhưng vẫn tinh tế Phong cách: Tối giản, hiện đại, trẻ trung Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, văn phòng, pantry, phòng chờ, không gian gia đình Ứng dụng: Quán cafe, quán trà sữa, nhà hàng, văn phòng sáng tạo, khu vực tiếp khách, không gian sinh hoạt chung', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-008-r-8.jpg', NULL, NULL, 'Đa dạng từ gam trung tính đến pastel trẻ trung, dễ phối hợp theo concept quán, tạo không gian sinh động nhưng vẫn tinh tế', 'Cao tổng thể 760mm × Rộng 600mm × Sâu 560mm', 'Bluewood', 'GCF-008', 'ghe-cafe-daily-gcf-008', NULL, NULL, 163),
(1010873, 'Ghế cafe DAILY GCF-013', 935000, 'Kích thước ghế: Cao tổng thể 800mm × Rộng 425mm × Sâu 460mm × Cao mặt ngồi 460mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế họa tiết đan chéo thoáng khí, mặt ngồi liền khối bo cong nhẹ, chân gỗ tự nhiên vát nhẹ tạo sự cân bằng Chất liệu: Thân ghế: Nhựa PP cao cấp, nhẹ, bền, chống ẩm, dễ vệ sinh Chân ghế: Gỗ tự nhiên chắc chắn, xử lý kỹ lưỡng, chịu lực tốt, hạn chế cong vênh Màu sắc: Đa dạng (vàng, xanh lá, xanh nhạt, đen, trắng, hồng pastel…), kết hợp nhựa màu nổi bật và chân gỗ tự nhiên, tạo tổng thể hài hòa, vừa hiện đại vừa ấm cúng Phong cách: Hiện đại, tối giản, Scandinavian, trẻ trung Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, phòng họp sáng tạo, showroom, khu vực tiếp khách Ứng dụng: Quán cafe, quán trà sữa, nhà hàng hiện đại, phòng ăn gia đình, văn phòng sáng tạo, khu vực chờ – tiếp khách', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-013-3.jpg', NULL, NULL, 'Đa dạng (vàng, xanh lá, xanh nhạt, đen, trắng, hồng pastel…), kết hợp nhựa màu nổi bật và chân gỗ tự nhiên, tạo tổng thể hài hòa, vừa hiện đại vừa ấm cúng', 'Cao tổng thể 800mm × Rộng 425mm × Sâu 460mm × Cao mặt ngồi 460mm', 'Bluewood', 'GCF-013', 'ghe-cafe-daily-gcf-013', NULL, NULL, 163),
(1001707, 'Ghế ăn LUNO GAN-045', 938000, 'Kích thước: Cao tổng 840mm, cao mặt ngồi 450mm, rộng mặt ghế 450mm, sâu mặt ghế 400mm, rộng toàn bộ 450mm, sâu toàn bộ 500mm Quy cách: Ghế ăn hiện đại, lưng và mặt ghế chần ô vuông caro sành điệu, lưng hơi cong ôm cơ thể, mặt ngồi rộng rãi, đệm dày êm ái, chân thép sơn tĩnh điện màu đen mờ thon gọn nhưng vững chắc Chất liệu: Bọc da PU cao cấp chống thấm, khung thép nguyên khối hoặc gỗ tự nhiên xử lý chống mối mọt, đệm mút đúc mật độ cao đàn hồi tốt, chân thép sơn tĩnh điện chống gỉ sét, có đế lót chống trượt Màu sắc: Xanh lá nhạt, Cam cháy, Xám tro (hoặc tùy chọn theo yêu cầu) Phong cách: Hiện đại, trẻ trung, năng động Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, văn phòng pantry, khách sạn, khu nghỉ dưỡng', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/1_GAN-045.jpg', NULL, 'Bọc da PU cao cấp chống thấm, khung thép nguyên khối hoặc gỗ tự nhiên xử lý chống mối mọt, đệm mút đúc mật độ cao đàn hồi tốt, chân thép sơn tĩnh điện chống gỉ sét, có đế lót chống trượt', 'Xanh lá nhạt, Cam cháy, Xám tro (hoặc tùy chọn theo yêu cầu)', 'Cao tổng 840mm, cao mặt ngồi 450mm, rộng mặt ghế 450mm, sâu mặt ghế 400mm, rộng toàn bộ 450mm, sâu toàn bộ 500mm', 'Bluewood', 'GAN-045', 'ghe-an-luno-gan-045', NULL, NULL, 162),
(1013220, 'Ghế văn phòng NEO GVP-028', 945000, 'Kích thước: Chiều cao mặt ngồi: 38–48 cm Rộng đệm: 47 cm Rộng lưng ghế: 44 cm Khoảng cách giữa 2 tay ghế: 58 cm Quy cách: Ghế văn phòng hiện đại – thiết kế gọn gàng, tinh tế, phù hợp nhiều không gian làm việc. Tay ghế gập tiện lợi, tiết kiệm diện tích. Chất liệu: Lưng lưới đàn hồi cao cấp: thoáng khí, hạn chế nóng bí Đệm mút bọc lưới: êm ái, đàn hồi tốt, ngồi lâu vẫn thoải mái Tay ghế nhựa gập linh hoạt: tiện lợi, dễ cất gọn Pitton thủy lực: nâng hạ chiều cao dễ dàng Chân sao nhựa đúc nguyên khối: chắc chắn, chịu lực tốt Bánh xe cao su: di chuyển nhẹ nhàng, giảm tiếng ồn, bảo vệ mặt sàn Phong cách: Hiện đại, tối giản, trẻ trung – phù hợp văn phòng công ty, phòng học tập, góc làm việc tại nhà.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-028-3.jpg', NULL, NULL, 'Đen, Màu', NULL, 'Bluewood', 'BLUEWOOD-1013220', 'ghe-van-phong-neo-gvp-028', NULL, NULL, 161),
(1010791, 'Ghế cafe DAILY GCF-011', 950000, 'Kích thước ghế: Cao tổng thể 825mm × Rộng 535mm × Sâu 485mm × Cao mặt ngồi 415mm Quy cách: Ghế nhựa PP phong cách hiện đại – tối giản, lưng ghế cong nhẹ ôm sát cơ thể, mặt ngồi rộng rãi bo tròn mềm mại, kiểu dáng liền khối thanh lịch Chất liệu: Thân ghế: Nhựa PP cao cấp, chịu lực tốt, chống cong vênh, nhẹ và dễ di chuyển Bề mặt: Nhẵn mịn, dễ lau chùi, hạn chế trầy xước Màu sắc: Đa dạng (trắng, đen, xanh dương, xanh lá, vàng, hồng, cam…), dễ phối hợp theo concept quán, tạo điểm nhấn sinh động Phong cách: Hiện đại, tối giản, trẻ trung, tinh tế Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, phòng họp, văn phòng sáng tạo, không gian gia đình Ứng dụng: Quán cafe, quán trà sữa, nhà hàng, coworking space, phòng họp, ban công, sân vườn có mái che, căn hộ chung cư', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-011-10.jpg', NULL, NULL, 'Đa dạng (trắng, đen, xanh dương, xanh lá, vàng, hồng, cam…), dễ phối hợp theo concept quán, tạo điểm nhấn sinh động', 'Cao tổng thể 825mm × Rộng 535mm × Sâu 485mm × Cao mặt ngồi 415mm', 'Bluewood', 'GCF-011', 'ghe-cafe-daily-gcf-011', NULL, NULL, 163),
(1010911, 'Ghế cafe DAILY GCF-014', 950000, 'Ghế cafe DAILY GCF-014 – Thiết kế hiện đại, bền đẹp cho mọi không gian Ghế cafe DAILY GCF-014 là lựa chọn lý tưởng cho quán cafe, nhà hàng, văn phòng và không gian gia đình theo phong cách hiện đại. Sản phẩm nổi bật với phần lưng tựa nhựa PP họa tiết thông thoáng, chân gỗ chắc chắn và kích thước tiêu chuẩn mang lại cảm giác ngồi thoải mái, ổn định và thẩm mỹ cao. Tổng quan sản phẩm ghế cafe DAILY GCF-014 Ghế cafe DAILY GCF-014 được thiết kế theo xu hướng nội thất tối giản, trẻ trung và linh hoạt trong phối màu. Phần lưng và mặt ngồi làm từ nhựa PP cao cấp, kết hợp cùng chân gỗ tự nhiên giúp sản phẩm vừa đảm bảo độ bền, vừa tạo điểm nhấn ấm áp cho không gian. Nhờ thiết kế gọn gàng và thanh thoát, mẫu ghế này dễ dàng sử dụng cho nhiều mục đích như ghế cafe, ghế bàn ăn, ghế tiếp khách hoặc ghế phòng họp phong cách sáng tạo. Thông số kỹ thuật ghế cafe DAILY GCF-014 Với chiều cao mặt ngồi 460 mm, ghế phù hợp với hầu hết các loại bàn cafe và bàn ăn tiêu chuẩn hiện nay, đảm bảo tư thế ngồi thoải mái và khoa học. Chất liệu bền bỉ, an toàn Nhựa PP cao cấp: Phần lưng và mặt ngồi được sản xuất từ nhựa PP có độ bền cao, chịu lực tốt và hạn chế cong vênh trong quá trình sử dụng. Bề mặt nhẵn mịn, dễ lau chùi, phù hợp với môi trường kinh doanh cần vệ sinh thường xuyên như quán cafe và nhà hàng. Thiết kế lưng tựa họa tiết thông thoáng giúp tạo độ thoáng khí, hạn chế cảm giác nóng lưng khi ngồi lâu. Chân gỗ chắc chắn: Chân ghế làm từ gỗ tự nhiên, có khả năng chịu lực tốt, đảm bảo độ ổn định khi sử dụng. Cấu trúc chân được liên kết chắc chắn với khung đỡ bên dưới mặt ghế, tăng độ bền và hạn chế rung lắc. Thiết kế hiện đại, dễ phối nội thất Ghế cafe DAILY GCF-014 sở hữu kiểu dáng tối giản nhưng tinh tế. Phần lưng cong nhẹ theo dáng người tạo cảm giác thoải mái khi tựa. Tông màu đa dạng giúp dễ dàng kết hợp với nhiều phong cách nội thất như: Phong cách Scandinavian Phong cách hiện đại Phong cách tối giản Không gian cafe trẻ trung, sáng tạo Thiết kế nhỏ gọn với chiều rộng 425 mm và c...', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-014-4.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GCF-014', 'ghe-cafe-daily-gcf-014', NULL, NULL, 163),
(1003842, 'Ghế phòng họp NEO GPH-005', 955000, 'Thiết kế hiện đại, sang trọng với lưng cao ôm sát cơ thể, hỗ trợ cột sống Khung thép mạ crom sáng bóng, chắc chắn, chống gỉ sét và chịu lực tốt Đệm ngồi và tựa lưng bọc vải lưới thoáng khí hoặc da PU cao cấp, êm ái và dễ vệ sinh Tay vịn tích hợp liền mạch với khung ghế, tạo sự chắc chắn và thẩm mỹ Kích thước tối ưu (W560 x D490 x H1050 mm), phù hợp nhiều không gian phòng họp và văn phòng hiện đại', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-005.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-005', 'ghe-phong-hop-neo-gph-005', NULL, NULL, 161),
(1003871, 'Ghế phòng họp NEO GPH-011', 960000, 'Thiết kế tối giản, tinh tế : Kích thước 112 x 48 x 46 cm, phù hợp vóc dáng người Việt, tay vịn liền mạch. Chất liệu cao cấp, bền bỉ : Khung sắt mạ crom chống gỉ sét, đệm và lưng ghế mút bọc vải/da công nghiệp. Thoải mái tối đa : Lưng ghế ôm sát đường cong cơ thể, hỗ trợ cột sống, giảm mỏi lưng khi ngồi lâu. Tiện ích linh hoạt : Trọng lượng vừa phải, dễ di chuyển, phù hợp cho phòng họp, văn phòng, tiếp khách hoặc gia đình. Độ bền và thẩm mỹ cao : Đường may tỉ mỉ, chống ăn mòn, dễ phối hợp với nhiều phong cách nội thất hiện đại.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-011.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-011', 'ghe-phong-hop-neo-gph-011', NULL, NULL, 161),
(1001681, 'Ghế ăn LUNO GAN-019', 961200, 'Kích thước: Rộng 450mm, sâu 500mm, cao 880mm, chiều cao mặt ngồi 470mm Quy cách: Ghế ăn hiện đại, lưng ghế chần ô vuông hoặc họa tiết hình thoi (kim cương) độc đáo, mặt ngồi rộng rãi, chân thép sơn tĩnh điện màu đen kết hợp bọc đồng sang trọng Chất liệu: Bọc da PU cao cấp, khung gỗ tự nhiên chắc chắn, chân thép sơn tĩnh điện bọc đồng, nệm mút đàn hồi cao Màu sắc: Kem nhạt tinh tế, Cam đất ấm áp, Xám hiện đại (hoặc tùy chọn theo yêu cầu) Phong cách: Hiện đại, sang trọng, đẳng cấp Ứng dụng: Ghế ăn, ghế cafe, ghế nhà hàng cao cấp, ghế làm việc, ghế tiếp khách, ghế trang điểm', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/2_GAN-019.jpg', NULL, 'Bọc da PU cao cấp, khung gỗ tự nhiên chắc chắn, chân thép sơn tĩnh điện bọc đồng, nệm mút đàn hồi cao', 'Kem nhạt tinh tế, Cam đất ấm áp, Xám hiện đại (hoặc tùy chọn theo yêu cầu)', 'Rộng 450mm, sâu 500mm, cao 880mm, chiều cao mặt ngồi 470mm', 'Bluewood', 'GAN-019', 'ghe-an-luno-gan-019', NULL, NULL, 162),
(1010903, 'Ghế cafe DAILY GCF-006', 990000, 'Kích thước ghế: Cao tổng thể 760mm × Rộng 600mm × Sâu 560mm Quy cách: Ghế nhựa nguyên khối phong cách hiện đại – tối giản, lưng tựa cong nhẹ, mặt ngồi rộng rãi, form dáng gọn gàng dễ phối hợp với bàn cafe phổ biến Chất liệu: Nhựa PP cao cấp, chịu lực tốt, bền bỉ, thích hợp cả trong nhà và ngoài trời Bề mặt nhựa mịn, hạn chế bám bẩn, dễ lau chùi Màu sắc: Đa dạng từ gam trung tính đến tông nổi bật, dễ phối hợp theo concept quán, tạo không gian trẻ trung – năng động Phong cách: Hiện đại, tối giản, cá tính Công năng: Ghế ngồi quán cafe, trà sữa, nhà hàng, sân vườn, ban công, không gian gia đình Ứng dụng: Quán cafe trẻ trung, quán trà sữa, nhà hàng, khu vực ngoài trời, setup quán chuyên nghiệp', 'Ghế sân vườn', 1, 'https://bluewood.vn/wp-content/uploads/2026/02/ghe-cafe-daily-gcf-006-1.jpg', NULL, NULL, 'Đa dạng từ gam trung tính đến tông nổi bật, dễ phối hợp theo concept quán, tạo không gian trẻ trung – năng động', 'Cao tổng thể 760mm × Rộng 600mm × Sâu 560mm', 'Bluewood', 'GCF-006', 'ghe-cafe-daily-gcf-006', NULL, NULL, 163),
(1013197, 'Ghế văn phòng NEO GVP-018', 999000, 'Kích thước: Cao tổng thể 88–98 cm × Cao chỗ ngồi 38–48 cm × Rộng phủ bì 60 cm × Sâu 47 cm Quy cách: Ghế văn phòng công thái học – thiết kế trẻ trung, hiện đại, phù hợp nhiều không gian (văn phòng, học tập, làm việc tại nhà, gaming nhẹ). Chất liệu: Lưng lưới thoáng khí + nệm mút: ngồi lâu không nóng bí, hỗ trợ lưng tốt Chân sao nhựa nguyên sinh: chắc chắn, chịu lực cao, bền bỉ Tay vịn nhựa PP gập lên xuống: tiện lợi, tiết kiệm diện tích Pistong nâng hạ: điều chỉnh chiều cao linh hoạt Bánh xe xoay 360°: di chuyển êm ái, hạn chế tiếng ồn Phong cách: Hiện đại, trẻ trung, công thái học – phù hợp nhân viên văn phòng, học sinh, sinh viên, freelancer. Ứng dụng: Văn phòng công ty, phòng học, góc làm việc tại nhà, không gian sáng tạo, setup gaming.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/05/ghe-van-phong-neo-gvp-018-1.jpg', NULL, NULL, NULL, 'Cao tổng thể 88–98 cm × Cao chỗ ngồi 38–48 cm × Rộng phủ bì 60 cm × Sâu 47 cm', 'Bluewood', 'BLUEWOOD-1013197', 'ghe-van-phong-neo-gvp-018', NULL, NULL, 161),
(1003872, 'Ghế phòng họp LUNO GPH-012', 1020000, 'Thiết kế sang trọng, hiện đại : Kích thước 55 x 55 x 90 cm, kiểu dáng thanh lịch, dễ phối hợp nội thất. Chất liệu cao cấp : Khung sắt mạ crom sáng bóng chống gỉ sét, đệm mút đàn hồi bọc da PU hoặc vải lưới. Công thái học hỗ trợ sức khỏe : Tựa lưng ôm sát, giảm áp lực cột sống và vai gáy khi ngồi lâu. Tiện ích linh hoạt : Trọng lượng vừa phải, dễ di chuyển và sắp xếp trong nhiều không gian phòng họp. Thẩm mỹ và bền bỉ : Dễ vệ sinh, chống ăn mòn, nâng tầm sự chuyên nghiệp cho không gian làm việc.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-012.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-012', 'ghe-phong-hop-luno-gph-012', NULL, NULL, 161),
(1001448, 'Ghế ăn LUNO GAN-025', 1026000, 'Kích thước: Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm Quy cách: Ghế ăn hiện đại, tựa lưng bo cong nhẹ ôm sát cơ thể, lưng ghế chần họa tiết chữ V độc đáo, chân sắt thanh mảnh sơn tĩnh điện chắc chắn Chất liệu: Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, nệm mút đàn hồi cao, phụ kiện chống trượt bảo vệ sàn Màu sắc: Cam trẻ trung, Xám đậm sang trọng, Kem tinh tế Phong cách: Hiện đại, năng động, sang trọng Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, phòng tiếp khách', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-025-1.jpg', NULL, 'Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, nệm mút đàn hồi cao, phụ kiện chống trượt bảo vệ sàn', 'Cam trẻ trung, Xám đậm sang trọng, Kem tinh tế', 'Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm', 'Bluewood', 'GAN-025', 'ghe-an-luno-gan-025', NULL, NULL, 162),
(1001586, 'Ghế ăn LUNO GAN-030', 1030000, 'Kích thước: Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm (Kích thước tối ưu cho nhiều không gian) Quy cách: Ghế ăn hiện đại, form dáng gọn gàng, tựa lưng bo cong ôm sát cơ thể, đường may ngang tinh tế, chân sắt thanh mảnh sơn tĩnh điện chắc chắn Chất liệu: Bọc da PU cao cấp chống thấm, khung chân sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc Màu sắc: Kem trung tính, Cam trẻ trung, Xám đậm sang trọng Phong cách: Hiện đại, tối giản, thanh lịch Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, lounge, phòng tiếp khách', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-030-2.jpg', NULL, 'Bọc da PU cao cấp chống thấm, khung chân sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc', 'Kem trung tính, Cam trẻ trung, Xám đậm sang trọng', 'Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm (Kích thước tối ưu cho nhiều không gian)', 'Bluewood', 'GAN-030', 'ghe-an-luno-gan-030', NULL, NULL, 162),
(1003873, 'Ghế phòng họp LUNO GPH-013', 1050000, 'Thiết kế sang trọng, hiện đại : Kích thước 48 x 46 x 112 cm, lưng cao, chân quỳ vững chắc, kiểu dáng thanh lịch. Chất liệu cao cấp : Khung sắt mạ inox sáng bóng chống gỉ sét, đệm và tựa lưng bọc da hoặc lưới thoáng khí. Thoải mái tối đa : Thiết kế công thái học, hỗ trợ tư thế ngồi chuẩn, giảm áp lực lên cột sống. Độ bền vượt trội : Khung inox chịu lực tốt, chống ăn mòn, tuổi thọ cao, dễ dàng vệ sinh. Ứng dụng linh hoạt : Phù hợp cho phòng họp, văn phòng, tiếp khách hoặc làm việc cá nhân, dễ phối hợp nội thất.', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/ghe-phong-hop-neo-gph-013.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GPH-013', 'ghe-phong-hop-luno-gph-013', NULL, NULL, 161),
(1001587, 'Ghế ăn LUNO GAN-031', 1058000, 'Kích thước: Cao tổng ~900mm, cao tựa lưng ~600mm, rộng ~480mm Quy cách: Ghế ăn tối giản, tựa lưng bo cong nhẹ ôm sát cơ thể, form dáng thanh thoát, màu sắc trung tính dễ phối Chất liệu: Vải bố dệt cao cấp thoáng khí, chống xù lông, khung ghế chắc chắn, chân gỗ tự nhiên bền đẹp, nhập khẩu nguyên chiếc Màu sắc: Xám đậm sang trọng, Kem nhã nhặn Phong cách: Hiện đại, tối giản, thanh lịch (Scandinavian, Minimalist, Contemporary) Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, lounge, phòng chờ', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-031-1.jpg', NULL, 'Vải bố dệt cao cấp thoáng khí, chống xù lông, khung ghế chắc chắn, chân gỗ tự nhiên bền đẹp, nhập khẩu nguyên chiếc', 'Xám đậm sang trọng, Kem nhã nhặn', 'Cao tổng ~900mm, cao tựa lưng ~600mm, rộng ~480mm', 'Bluewood', 'GAN-031', 'ghe-an-luno-gan-031', NULL, NULL, 162),
(1001542, 'Ghế ăn LUNO GAN-037', 1060000, 'Thiết kế thanh lịch & độc đáo : Lưng ghế hơi ngả, ôm sát cơ thể, điểm nhấn chần trám hoặc may dọc, phối màu tinh tế giữa mặt ghế và viền lưng. Chất liệu cao cấp : Da PU hoặc vải dệt cao cấp, khung gỗ tự nhiên hoặc thép cường lực, chân gỗ hoặc thép giả gỗ, đệm mút đàn hồi cao. Công năng tiện ích : Êm ái, hỗ trợ cột sống, dễ vệ sinh, chống thấm (với da PU), chống trầy sàn, trọng lượng vừa phải dễ di chuyển. Không gian sử dụng linh hoạt : Phù hợp phòng ăn, nhà hàng, quán café, lounge, văn phòng; phối hợp tốt với bàn đá, gỗ, kính.', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-037-1.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GAN-037', 'ghe-an-luno-gan-037', NULL, NULL, 162),
(1001447, 'Ghế ăn LUNO GAN-024', 1069000, 'Kích thước: Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm Quy cách: Ghế ăn hiện đại, tựa lưng bo cong công thái học, phối màu thời thượng (cam đất – kem – nâu), đường may chữ V tinh xảo, chân sắt thanh mảnh sơn tĩnh điện chắc chắn Chất liệu: Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc Màu sắc: Kem tinh tế, Cam đất cá tính, Nâu sang trọng Phong cách: Hiện đại, tối giản, sang trọng Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, phòng tiếp khách', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-024-4.jpg', NULL, 'Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc', 'Kem tinh tế, Cam đất cá tính, Nâu sang trọng', 'Cao tổng ~950mm, cao tựa lưng ~650mm, rộng ~480mm', 'Bluewood', 'GAN-024', 'ghe-an-luno-gan-024', NULL, NULL, 162),
(1001512, 'Ghế ăn LUNO GAN-027', 1080000, 'Kích thước: Cao tổng ~850mm, cao tựa lưng ~550mm, rộng ~480mm Quy cách: Ghế ăn hiện đại, tựa lưng thấp bo cong công thái học, dáng ghế thanh thoát gọn nhẹ, góc nghiêng tự nhiên thoải mái Chất liệu: Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc Màu sắc: Xám đậm sang trọng, Kem nhẹ nhàng Phong cách: Hiện đại, tối giản, phóng khoáng Ứng dụng: Ghế ăn gia đình, ghế cafe, ghế nhà hàng, lounge, phòng chờ', 'Ghế nhà hàng', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/gan-027-1.jpg', NULL, 'Bọc da PU cao cấp chống thấm, khung sắt sơn tĩnh điện bền bỉ, phụ kiện chống trượt bảo vệ sàn, nhập khẩu nguyên chiếc', 'Xám đậm sang trọng, Kem nhẹ nhàng', 'Cao tổng ~850mm, cao tựa lưng ~550mm, rộng ~480mm', 'Bluewood', 'GAN-027', 'ghe-an-luno-gan-027', NULL, NULL, 162),
(1001514, 'Ghế Ăn LUNO GAN-041', 1100000, 'Thiết kế sang trọng & nghệ thuật : Lưng ghế cong ôm sát, khung thép ôm lưng độc đáo, đường may chần tinh tế, dáng ghế thanh thoát. Chất liệu cao cấp : Da PU mềm mại chống thấm, khung gỗ tự nhiên chống mối mọt, chân thép sơn tĩnh điện chống gỉ, nệm mút đàn hồi cao. Công năng tiện ích : Ngồi êm ái, hỗ trợ cột sống, dễ vệ sinh, chịu lực tốt, giữ dáng lâu dài. Không gian sử dụng linh hoạt : Phù hợp phòng ăn, quán café, nhà hàng, phòng họp, ghế làm việc tại nhà; màu sắc đa dạng dễ phối nội thất.', 'Bluewood', 1, 'https://bluewood.vn/wp-content/uploads/2025/12/2_GAN-041.jpg', NULL, NULL, NULL, NULL, 'Bluewood', 'GAN-041', 'ghe-an-gan-luno-041', NULL, NULL, 1),
(1014176, 'Ghế văn phòng NEO GVP-043', 1100000, 'Kích thước: 49 × 50 × 100 cm – gọn gàng, phù hợp nhiều không gian làm việc. Quy cách: Ghế xoay văn phòng hiện đại – lưng lưới thoáng khí, đệm mút cao cấp, khung thép chắc chắn, gam màu trắng trang nhã. Chất liệu: Lưng lưới cao cấp: thoáng khí, ôm sát cột sống Đệm mút dày đàn hồi: ngồi lâu không mỏi, giữ form tốt Khung thép chắc chắn: chịu lực cao, ổn định Chân sao 5 cánh + bánh xe xoay 360°: di chuyển linh hoạt Phong cách: Hiện đại – tối giản – tinh tế. Dễ phối hợp với phong cách Minimalism , Modern , Contemporary .', 'Nội thất văn phòng', 1, 'https://bluewood.vn/wp-content/uploads/2026/06/ghe-van-phong-neo-gvp-043-2.jpg', NULL, NULL, NULL, '49 × 50 × 100 cm – gọn gàng, phù hợp nhiều không gian làm việc.', 'Bluewood', 'BLUEWOOD-1014176', 'ghe-van-phong-neo-gvp-043', NULL, NULL, 161);
