INSERT INTO product_specifications (id, spec_key, spec_label, spec_value, display_order, product_id) VALUES
(1, 'kich-thuoc-ghe', 'Kich thuoc', 'Cao tổng thể 820mm × Rộng 460mm × Sâu 500mm × Cao mặt ngồi 450mm', 0, 1011681),
(2, 'quy-cach', 'Quy cach', 'Ghế nhựa phong cách hiện đại – tối giản, lưng tựa cong nhẹ nâng đỡ lưng, mặt ngồi vừa vặn cân đối, kiểu dáng gọn gàng tối ưu diện tích.; Chất liệu; Khung nhựa cao cấp, chịu lực tốt, chống cong vênh.; Chống ẩm, chống mối mọt, bề mặt nhẵn mịn dễ vệ sinh.; Trọng lượng nhẹ, dễ di chuyển và sắp xếp.', 1, 1011681),
(3, 'phong-cach', 'Phong cach', 'Hiện đại, tinh tế, dễ phối hợp với nhiều phong cách nội thất (Scandinavian, Minimalist, Vintage).', 2, 1011681),
(4, 'cong-nang', 'Cong nang', 'Ghế ngồi cho quán cafe, trà sữa, nhà hàng, phòng ăn gia đình, văn phòng, showroom, homestay, khu vực chờ.', 3, 1011681),
(5, 'ung-dung', 'Ung dung', 'Linh hoạt cho nhiều không gian, phù hợp môi trường có tần suất sử dụng cao, tối ưu chi phí đầu tư.', 4, 1011681),
(6, 'quy-cach', 'Quy cach', 'Ghế văn phòng hiện đại – thiết kế tối giản, thoáng khí, phù hợp nhiều không gian làm việc (văn phòng, phòng họp, học tập tại nhà, startup).; Chất liệu; Lưng nhựa bọc lưới: thoáng khí, có cơ chế gật gù thư giãn; Đệm mút bọc lưới: êm ái, đàn hồi tốt, giữ form lâu dài; Tay ghế nhựa cong cố định: chắc chắn, hỗ trợ tư thế tự nhiên; Piston thủy lực: nâng hạ chiều cao linh hoạt; Chân sao nhựa đúc: chịu lực tốt, bền bỉ; Bánh xe nhựa bọc cao su: di chuyển nhẹ nhàng, giảm tiếng ồn, bảo vệ mặt sàn', 0, 1013241),
